INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8539676','Молитва за бійців','Музика: Василь Романюк Слова: Ольга Калина','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Василь Романюк.','Звертаюсь до Тебе, Ісусе, Син Божий,
Мою Україну спаси, захисти!
Я вірю і знаю, що Ти допоможеш
Нам до перемоги скоріше прийти!

Спаси, я благаю, бійців України,
Що зараз на фронті в запеклих боях,
Щоб жоден синочок чи донька не згинув,
Вкажи Ти їм, Боже, всім праведний шлях!

Спаси їх, Ісусе, від куль і полону,
Ворожих катівень, гіркої сльози.
Бійці хай вернуться живими додому,
Помилуй, мій Боже, усіх і прости!

Ти завжди будь поряд у кожну хвилину,
Тримай всіх за руку й на світло веди,
Ми хочемо правди, ми прагнемо миру.
Мою Україну, мій Боже, спаси!','[''pisni.org.ua'', ''cat:christ'', ''Пісні до Ісуса Христа'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8539676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8539676','Молитва за бійців','Звертаюсь до Тебе, Ісусе, Син Божий,
Мою Україну спаси, захисти!
Я вірю і знаю, що Ти допоможеш
