INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8561272','Ти - мій друг','Музика: Lomiy Слова: Lomiy','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Ти - мій друг назавжди,
Не раз ти поруч у біді!
Коли світ навкруги замовкає,
Твоя тиша мене зігріває.
Ти - мій друг назавжди,
Не раз ти поруч у біді!
Ти не клявся - ти просто був,
Тому ти мене не забув!

Ми йдемо через роки,
Долаємо свій шлях.
Коли руйнує біль,
Вчимось на помилках.
Летять роки, часи та дні,
Тримаємося разом в цій грі,
Не чутно серця стук,
Я відчуваю поруч тебе, друг!

Приспів.

Колись давно зійшлись,
В цьому світі знайшлись,
Шторми життєві кожен раз
Хитають віру в нас...
Ти рятував мене не раз!
Ти - мій друг, -
І це не змінить час!
Ти - той, хто зрозуміє й допоможе,
Ця дружба всі печалі переможе!

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8561272'), datetime('now')),datetime('now'));
