INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8552714','Не в тому суть','Музика: Назад в майбутнє Слова: Назад в майбутнє','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Спини бажання, не спіши!
Воно згорить у глибині,
Не клич мене і не підходь,
Осінній день усе забрав...
Я не прошу, вернись назад,
Між нами - тиша й листопад,
Моя душа вже не болить,
Та тінь того дня не згасає...

Приспів:
Не в тому суть, не в тому суть,
Що ніч зависла у вікні,
А в тім, що стали ми чужі,
Різні серця, як ніч і день...
Це не любов, а тінь журби,
Це біль прощання без доби...
Як пізня осінь без тепла,
Де згасла мрія, що жила!..

На гілці - намисто з плодів,
Осінній сум в душі засів.
Ти іншу вже тримаєш там,
А я мовчу новим вітрам...
Я не прошу, вернись назад,
Між нами - тиша й листопад,
Моя душа вже не болить,
Та тінь того дня не згасає...

Приспів. (2)

Це не любов, а тінь журби,
Це пізня осінь назавжди...','[''pisni.org.ua'', ''cat:devoted'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8552714'), datetime('now')),datetime('now'));
