INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8536654','Різдвяна пісня','Музика: Катерина Плескач Слова: Катерина Плескач','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Проходжу десь околицею сніжного міста,
Та вулиця вночі від посмішок зігріта,
Біжить додому дівчина щаслива,
Навколо всі очікують якогось дива!..
Різдвяну пісню грають музиканти,
З нотами суму, як час може так мчати?
Хтось вийшов сам у пізній час блукати, |
Бо хочеться знов на душі               |
Дитинство відчувати...                 | (2)

Приспів:
Мелодія різдвяна лине,
Історія так швидко плине,
Давай станцюємо ми
В перший снігопад!
І колотіння те не стихне,
Допоки блиск в очах не зникне,
Ми рік цей проживем
Без жодних вад!

У ніч казкову бажання загадаю.
Щоб на Різдво з тобою бути разом!
Хай буде щастя більше, я прохаю,       |
І спільні миті наші                    |
Не забудуться з часом!                 | (2)

Приспів. (2)

І колотіння те не стихне,
Допоки блиск в очах не зникне,
Ми рік цей проживем
Без жодних вад!','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8536654'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8536654','Різдвяна пісня','Проходжу десь околицею сніжного міста,
