INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_85676','Волоцюга',NULL,'uk','ukraine_1991',NULL,NULL,'Співаник тернопільського туристичного клубу "Кристал"',NULL,'Гей, волоцюго, де ти волочишся,
Що ти си думаєш там.
Одяг твій тертий,
Наплічник подертий,
А серце відкрите вітрам.

Серце гаряче вітри холодять,
А голову миють дощі.
Ти всюди мандруєш,
Де прийдеш ночуєш,
Для тебе навколишній світ.

Комфорт не для тебе
І м''яка канапа -
Усе пролетіло, мов сон.
Лиш зоряне небо і ватра під боком,
І пісень чудовий бутон.

А в місті людному,
А в місті ситому,
Де душі закуті в асфальт.
Там жити несила -
Ти звідти тікаєш
На волю у первісний край.

Не смійте по ньому молебен справляти,
За душу співати пісень.
Він ще повернеться,
Він прийде у гості -
І усміх засяє, мов день.','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_85676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_85676','Волоцюга','Гей, волоцюго, де ти волочишся,
Що ти си думаєш там.
Одяг твій тертий,
Наплічник подертий,
А серце відкрите вітрам.

Серце гаряче вітри холодять,
А голову миють дощі.
Ти всюди мандруєш,
Де прийдеш ночуєш,
Для тебе навколишній світ.

Комфорт не для тебе
І м''яка канапа -
Усе пролетіло, мов сон.
Лиш зоряне небо і ватра під боком,
І пісень чудовий бутон.

А в місті людному,
А в місті ситому,
Де душі закуті в асфальт.
Там жити несила -
Ти звідти тікаєш
На волю у первісний край.

Не смійте по ньому молебен справляти,
За душу співати пісень.
Він ще повернеться,
Він прийде у гості -
І усміх засяє, мов день.');
