INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8560501','Зрозумій','Музика: ШІ Слова: Олена Рассуждай','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Зрозумій,
Не всяк, хто поруч, - твій єдиний...
Не жалій
За тим, хто серцю не причинний!..
Краще йти,
Ніж зупинитись на чужому...
Не знайти,
Але не зрадити нікому!..

Приспів:
Як знайдеш —
Впізнаєш ти своє відразу!
І збагнеш,
Яке це щастя бути разом!
Ваш вогонь
В пітьмі відразу запалає!
Тільки з ним
Душа кохання відчуває!

Хай сама,
Але без пута і облуди!..
Краще так,
Ніж у чужих шукати чуда...
Хай болить,
Але лишається правдиве!..
Не горить,
А лиш цвіте усе важливе!..

Приспів.

Ти молись,
Щоб не торкнутись більш чужого,
І колись
Дорога приведе до свого!..
І прийде
Той, що відчує все без слова,
Принесе
Кохання щире і чудове!..

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8560501'), datetime('now')),datetime('now'));
