INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8560219','Ти не моя, і я вже не твій','Музика: Пісня роду Слова: Пісня роду','uk','ukraine_1991',NULL,'2025','авторське подання','Пісня про любов, що зникла, залишивши лише спогади. "Ти не моя, і я вже не твій" — рядок, який говорить усе. Це історія розлуки, внутрішньої тиші та прийняття. Легкий відтінок шансону, емоційний вокал і щира лірика створюють атмосферу, яка не залишить байдужим. Пісню виконує Пісня роду (альбом: Збірка ніжних пісень про кохання 2025).','Приспів:
Ти не моя, і я вже не твій...
Між нами лиш спогади тіні слів...
Все, що палало, згоріло за мить...
Любов відпустили, хай далі летить!..

Твої очі, мов дощ уночі,
Залишили слід, що вже не болить...
Ми мовчали про головне,
І в тій тиші ми забули про все...
Ти шукала любов у чужих очах...
А я тишу шукав там, де було мовчання...
Наші серця - два різні, наші шляхи,
Що не зійдуться ніколи більше в житті...

Приспів.

Тепер ми - незнайомці у чужих містах...
Моє серце не забуло, як тебе любить!..
Кожен раз намагаюся забути тебе,
Але серце не може відпустити тебе...
Ми збудували любов удвох на піску.
Вітер нас не питав, чи надовго ми тут.
Ти своє, я своє життя проживу,
І у тиші хай час покладе цьому край.

Приспів.    Пісня Роду','[''pisni.org.ua'', ''cat:all-ukraine'', ''Загальноукраїнські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8560219'), datetime('now')),datetime('now'));
