INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8572950','Білки','(Через нашоє село). Музика: Степан Гіга Слова: Степан Гіга. Виконує: Степан Гіга','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Горі селом ідеме, співаєме файно,
Нас звідають чи з Білок
Ми кажеме айно.
Ци горі ци долі та все єдно Білки! |
Ниє нигде як у нас,                |
Хоч би ходив скільки!              | (2)

Ой, на свадьбі у селі
Музика заграла, мене, хлопця легіня,
Сусіда застала,
Через нашоє село тече річка Білка! |
Ни старіші ни жона,                |
А й бо вже й не дівка!             | (2)

Много читаних люди
Йся земля вродила,
Та сто років первим
Є жито молотила.
Лем у нас, лем у нас,              |
Правда говориться:                 |
Вать музика вать силач,            |
Кожен день годиться.               | (2)

Гоп, шідіріді дана!

Ци горі ци долі та все єдно Білки! |
Ниє нигде як у нас,                |
Хоч би ходив скільки!              | (2)','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8572950'), datetime('now')),datetime('now'));
