INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8573256','Шиншила','Музика: Тетяна Міронова, Костянтин Веретенніков Слова: Тетяна Міронова, Костянтин Веретенніков. Виконує: Тіна Кароль','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мій перший день без красок,
Я цілий день одна.
Біль невимовний, я в трансі,
І надтонка межа...
І от одна я, одна я...
Замерзаю одна я...

Приспів:
Ця божевільна зима
Снігом запорошила,
Я пришила тебе сама,
Я нагрішила, Шиншила.
Ця завірюха-зима
Снігом запорошила.
Я пришила тебе сама,
Приворожила шиншила...

Сонце зайшло за хмари,
Місто сумує, мовчить,
Милий, не муч, коханий,
Вирішив йти, то йди!..
І от одна я, одна я...
Замерзаю одна я...

Приспів. (2)','[''pisni.org.ua'', ''cat:devoted'', ''cat:zahalni-cinnosti'', ''Пісні присвячені окремим особам'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8573256'), datetime('now')),datetime('now'));
