INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_85807','Мамина казка','Музика: Олександр Жилінський Слова: Олексій Кононенко. Виконує: Павло Зібров','uk','ukraine_1991',NULL,NULL,'Пісенник "Червона Рута", Київ "Музична Україна" 1993',NULL,'Мій дім, моя хатина, моя хата,
