INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8572205','Різдво','Музика: Kyrylo Pariienko Слова: Artem Martyka','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Стривай, чекай, чи я ще сплю?..
Цей рік зустрів, вже проводжу.
Я тільки-тільки розпочав,
А зараз руку жму.
Чи то напевно все проспав,
У сні святкуючи свій голод,
Я наловив достатньо гав,
Дивлюсь на дворі вже Різдво!

Приспів:
Якщо і ти весь рік проспав,
Тоді вперед мерщі, бігом,
Ти, як Неймар, штрафні, пірнай
У Новий рік і у Різдво!
Ніхто не дасть тут жовтої
Тут всі з тобою за одно
Це переможний Новий рік!
Це наше праймове Різдво!

І ці свята я не просплю!
Їх святкувати розпочну!
В штрафну із новорічних свят
Я, як Неймар пірну!
Пробив той час, настав той день,
Ти подивися у вікно:
Чарівний вариться глінтвейн,
Казкове крутиться кіно!

Приспів.','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8572205'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8572205','Різдво','Стривай, чекай, чи я ще сплю?..
Цей рік зустрів, вже проводжу.
Я тільки-тільки розпочав,
А зараз руку жму.
Чи то напевно все проспав,
У сні святкуючи свій голод,
Я наловив достатньо гав,
Дивлюсь на дворі вже Різдво!

Приспів:
Якщо і ти весь рік проспав,
Тоді вперед мерщі, бігом,
Ти, як Неймар, штрафні, пірнай
У Новий рік і у Різдво!
Ніхто не дасть тут жовтої
Тут всі з тобою за одно
Це переможний Новий рік!
Це наше праймове Різдво!

І ці свята я не просплю!
Їх святкувати розпочну!
В штрафну із новорічних свят
Я, як Неймар пірну!
Пробив той час, настав той день,
Ти подивися у вікно:
Чарівний вариться глінтвейн,
Казкове крутиться кіно!

Приспів.');
