INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_85950','Жінка другова','Музика: Олександр Смик Слова: Олександр Смик. Виконує: Чорні черешні, Юрій Поліщук, Волинський народний хор','uk','ukraine_1991',NULL,'2006','1. Аудіо-CD "Кожен в серці солдат. Пісні поета-пісняра Олександра Смика." (2006) 2. Звитяга. Книжечка учасника табору.- 2002','В оригіналі пісня виконується з Em. Підбір акордів: bohdanko (pisni.org.ua)','Жив та був собі козак-  зірвиголова.
Та сподобалась йому жінка   другова...
Та сподобалась йому жінка другова.

Ніби й досі і не жив, відшукав траву —
Попри Бога зворожив жінку другову.  (2)

Довелись іти на Січ під хоругвами.
Та не з ним були в ту ніч жінка другова.  (2)

Сумно шабельки дзвенять, пил та згарище.
Ідуть на ворожу рать два товариша.  (2)

Втричі більше ворогів. Друг знесилений.
Пролунало поміж гір: "Прощай, милая!"  (2)

Козак коника обняв, б''є попругою.
Кулю на себе прийняв, яка другові.  (2)

Поверталися на Січ під хоругвами.
Гірко плакала в ту ніч жінка другова.  (2)

Акорди в "Dm" (для середнього голосу):

Жив та був собі козак-  зірвиголова.
Та сподобалась йому жінка   другова...
Та сподобалась йому жінка другова.','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_85950'), datetime('now')),datetime('now'));
