INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_861312','Брате!','Музика: Дейтерій Слова: Спиридон Черкасенко. Виконує: Дейтерій','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'відеозапис власна пам*ять','приспів (всюди) краще грати з баре, а куплети без. Підбір акордів: назарко','Вони ідуть у лавах щільних
Вперед, вперед і не один
Упав, як ти в огнях свавільних
Під спів червоних хуртовин.

Благослови ж їх, льот шалений,
Умри з усміхом на устах
Не поведе більш кат скажений
Твоїх братів у кайданах!

Приспів (лірично):
Ти впав, мій брате, в ранах
Між трупами таких, як сам.
Та не останній в могіканах,
Борониш ти святий вігвам.

Коли ж здригнуть міцні їх лави,
Коли не схочуть умирать, -
Покрий тавром ганьби й неслави,
Спали пожежею проклять!

Приспів (в ритмі куплетів):
Ти впав, мій брате, в ранах,
Між трупами таких як сам.
Та не останній в могіканах,
Борониш ти святий вігвам!','[''pisni.org.ua'', ''cat:istorychni'', ''cat:kruty'', ''Історичні пісні'', "Пісні пам''яті Героїв бою під Крутами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_861312'), datetime('now')),datetime('now'));
