INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8568450','Лелій','Музика: Павло Яворський, Ostap Drivko Слова: Павло Яворський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Боже, як ти красива,
Як передодня зливи
На переломі часу
Без крику, без страху!
