INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_862373','Осінній день, осінній день, осінній!','Музика: Ольга Богомолець Слова: Ліна Костенко. Виконує: Ольга Богомолець, Наталя Криничанка, Ліля Кобільник','uk','ukraine_1991',NULL,NULL,'1. Ліна Костенко. Сад нетанучих скульптур. — К.: Радянський письменник, 1987. — 208 с.','До тексту так і проситься музика. Ця пісня — своєрідний рекордсмен за числом створених мелодій. Ліля Кобільник виконує пісню на свою, відмінну мелодію.','Осінній день, осінній день, осінній!
О синій день, о синій день, о синій!
Осанна осені, о сум! Осанна.
Невже це осінь, осінь, о! — та сама.
Останні айстри горілиць зайшлися болем.
Ген килим, витканий із птиць, летить над полем.
Багдадський злодій літо вкрав, багдадський злодій.
І плаче коник серед трав — нема мелодій...','[''pisni.org.ua'', ''cat:bardivski'', ''cat:krasa-pryrody'', ''cat:nostalgia'', ''cat:romansy'', ''Бардівські пісні'', ''Пісні про красу природи'', ''Пісні з ностальгічними мотивами'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_862373'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_862373','Осінній день, осінній день, осінній!','Осінній день, осінній день, осінній!
О синій день, о синій день, о синій!
Осанна осені, о сум! Осанна.
Невже це осінь, осінь, о! — та сама.
Останні айстри горілиць зайшлися болем.
Ген килим, витканий із птиць, летить над полем.
Багдадський злодій літо вкрав, багдадський злодій.
І плаче коник серед трав — нема мелодій...');
