INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8575','Ластівка','(Прилетіла ластівка). Музика: Олександр Білаш Слова: Михайло Ткач. Виконує: Павло Дворський, Олександр Таранець','uk','ukraine_1991',NULL,NULL,'1. Збірник пісень Студентського Братства Львівської політехніки. Львів, 2000. 2. Українські пісні / Уклад. О. В. Зав’язкін.– Донецьк: ТОВ ВКФ "БАО", 2003.– 512 с.','Текст із акордами - із джерела 1. Ноти з акордами - із джерела 2. Текст виправлено за джерелом 2. Тут у джерелі 1 інакше: * Прилетіла ластівка з голубою ласкою... ** Вже останню кригу віднесла вода...','До вікна мойого теплий промінь ластиться,
Синьооке небо в шибку загляда, -
Прилетіла ластівка   голубою ласкою *   |
До моєї хати, до свого гнізда.          | (2)

Ластівка щебече під моєю стріхою,
Від зорі до ночі човником снує.
Весняною втіхою і любов''ю тихою           |
Облітає серце молоде моє.                 | (2)

Дівчинонько горда, глянь, як промінь ластиться,
Вже останню кригу понесла вода.**
Прилетіла ластівка голубою ласкою *       |
До моєї хати, до свого гнізда.            | (2)

Не лишай так скоро мого двору, ластівко,
Ти, холодний вітре, не тривож села, -
Дай напитись ласкою, дай нажитись казкою, |
Та не дай зазнати літа без тепла.         | (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:romansy'', ''Пісні про красу природи'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8575'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8575','Ластівка','До вікна мойого теплий промінь ластиться,
Синьооке небо в шибку загляда, -
Прилетіла ластівка   голубою ласкою *   |
До моєї хати, до свого гнізда.          | (2)

Ластівка щебече під моєю стріхою,
Від зорі до ночі човником снує.
Весняною втіхою і любов''ю тихою           |
Облітає серце молоде моє.                 | (2)

Дівчинонько горда, глянь, як промінь ластиться,
Вже останню кригу понесла вода.**
Прилетіла ластівка голубою ласкою *       |
До моєї хати, до свого гнізда.            | (2)

