INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_863714','Каштановий вальс','Музика: Олександр Злотник Слова: Олександр Вратарьов. Виконує: Віктор Павлік','uk','ukraine_1991',NULL,NULL,'http://gorodzelenogocveta.narod.ru',NULL,'Біля нашої школи,
Наче друзі, каштани
Нас вітали з тобою
Стільки раз, стільки раз!
І тобі і мені
Все знайоме навколо,
Нас кружля до світанку
Останній каштановий вальс.

Приспів:
Вальс шкільний на прощання -
Як замріяна зоряна тайна.
Все на світі минає,
Не повернеться знов!
Вальс шкільний на прощання
Як замріяна зоряна тайна, -
Що дарує нам юність
І перша юнацька любов,
І перша найсправжня любов.

Мабуть з першого класу,
В наших мріях цей день ми чекали.
Непомітно і швидко
Минув час, минув час.
І сьогодні тебе
Кличу я до святкової зали,
І танцюю з тобою
Останній каштановий вальс.

