INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8579116','Хлопців рота','Музика: Ruslan Nota Слова: народні, Ruslan Nota. Виконує: Людмила Клименко','uk','ukraine_before_1917',NULL,NULL,'авторське подання','Po Cimbalam Records — студія звукозапису повного циклу. Po Cimbalam Records — це професійна студія звукозапису, яка спеціалізується на створенні ексклюзивних аранжувань, авторських треків та високоякісних кавер-версій. Наші роботи звучать на радіо, телебаченні, у соцмережах та на великих онлайн-платформах. Ми працюємо з артистами різного рівня — від початківців до професіоналів. Індивідуальний підхід з душею — кожен проєкт опрацьовуємо максимально уважно та творчо. Для нас найважливіше — ідеальний кінцевий результат, який повністю задовольнить замовника та буде гідно звучати у будь-якому форматі. Ми пропонуємо: ✔ створення аранжувань (будь-які стилі) ✔ повний цикл продакшену (запис, зведення, мастеринг) ✔ адаптацію текстів / авторські пісні ✔ озвучення, джингли, музичні підкладки ✔ виробництво каверів "під ключ" Створимо музику, яка відрізняється. Po Cimbalam Records — коли важлива якість. https://studio.youtube.com/video/qN2DXnZ7kBU/edit Приклади: https://open.spotify.com/track/5ceoaRuULyRwmSnaF5V7lL?si=52a5d8f1d86e44e0 https://open.spotify.com/track/7jgkbaXlnDnHyjnEdU9Pn','Hey! Hey! Hey!

Приспів:
Колись в мене була,
Колись в мене була хлопців рота!
Не одному я дала,
Не одному я дала коло плота!
Коло плота, коло плота
Я давала ніжний, ніжний поцілунок,
А кому не пам''ятаю, бо збився рахунок!..

Цілу ніч не спала, цілу ніч не спала,
З хлопцями стояла, ніжно цілувала,
Колись була осінь, а тепер зима,
Колись були танці, а тепер нема,
Залицяли хлопці кожну ніч мене,
Хто би міг сказати, що той час мине!..

Приспів.

Осінь вже настала, осінь вже настала,
І зів''яли квіти, що ж його робити?..
Вже усі дорослі, вже повиростали діти,
Вже усі чекають, щоб принести мамі квіти.
Вже роки минули, не вернути знову,
Не вернути більше молодість чудову...
Hey! Hey! Hey!

Приспів. (2)','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8579116'), datetime('now')),datetime('now'));
