INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_864603','Зупинись','Музика: Ольга Богомолець Слова: Ольга Богомолець. Виконує: Ольга Богомолець','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ще один день пройшов, ще один крок до краю.
Він пролетів, як птах, так все життя мине.
Краплина в морі днів, так зірка загасає,
Так дивний світ життя в моїх очах засне.

Приспів:
Зупинись на мить, бо життя мине,
Подивись на світ, пригорни мене,
Візьми з моїх рук віру і любов,
І той біль пройде, ти повіриш знов, знов.

Чи вдосталь принесла тобі роси на віях?
Чи досить розділила твоєї сивини?
Загоїть рани всі, зігріти чи зуміла?
Чи ти чекаєш знов в моїх очах весни?

Приспів.

Ми всі в однім човні, нас човен вирушає
В тернисту дальну путь під вітер, в дощ і  град.
І де наш шлях пройде - ніхто того не знає.
Зазнаємо ще скільки ми сліз, розлук і втрат?

Приспів.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_864603'), datetime('now')),datetime('now'));
