INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8577312','Пісня комбайнера','Музика: Яків Цегляр Слова: Олекса Новицький','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ми виходим з коханою в поле,
Тільки променем бризне ясна зоря.
Ой, які в нас широкі роздолі,
Урожаю просторі моря.

Приспів:
Гей, пшениченько, нижче клонися,
Ти, дівчино, мені усміхнися!
Мій комбайне, пливи з краю в край,
Ми багатий зберем урожай,
Золотий урожай!

І з тобою, дівчинонька вірна,
Засівали ми разом свої поля.
Засівали ми зерном добірним,
Щоб розквітла українська земля!

Приспів.

І лунають пісні на роздоллі,
Майорить хустина в далі твоя.
Ой, же гарно в широкому полі
І з тобою, подруго моя!

Приспів.','[''pisni.org.ua'', ''cat:obzhynkovi'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8577312'), datetime('now')),datetime('now'));
