INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_861307','Блажен той муж','Музика: Едуард Драч. Виконує: Едуард Драч','uk','ukraine_1991',NULL,NULL,'від автора',NULL,'Блажен той муж, що Господа боїться -
Насіння його сильне на землі.
Рід безневинний поблагословиться
Достатком в домі, хлібом на столі.
І його правда буде з ним віками -
Вогонь і в темряві праведному є.
Ласкавий сам, він добрими руками
Братам позичить, вбогим подає.

Блажен той муж, що заповіді любить -
Зміцнила правда усі діла його.
Він не схибнеться, він весь вік пробуде
У світлі праведнім образу свого.
Лихая думка серце обминає -
На Бога ж уповання всіх зміцнить.
А Бог нещастям ворогів карає,
А він це бачить, Господа славить!

Блажен той муж, що Господа боїться
І в щедрості убогим подає.
І правда в його домі, наче криця,
І сила його сонцем повстає.
Во гніві тане заздрісник-небога -
Зубовний скрежет, і жаль в його очах...
Блажен той муж, що убоїться Бога!
Безбожна ж хіть розтане, як свіча!','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_861307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_861307','Блажен той муж','Блажен той муж, що Господа боїться -
Насіння його сильне на землі.
Рід безневинний поблагословиться
Достатком в домі, хлібом на столі.
