INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_86256','Любисток','Музика: Олександр Білаш Слова: Степан Пушик. Виконує: Дмитро Гнатюк','uk','ukraine_1991',NULL,NULL,'О.Білаш "Любисток" Київ "Музична Україна" 1970',NULL,'Синь Карпатських гір і синь небес,
І дівочі оченята сині.
Я шукав у горах едельвейс,
А знайшов любисток в полонині.

Приспів:
Полонина, полонина
Ловить зорі, сині зорі,
А гуцулка, а гуцулка полонила
Юне серце в Чорногорі.

В селах засвітилися вогні -
Ніч на гори опустила крила.
Дівчина зустрілася мені
І любисток ніжно попросила.

Приспів.

З неба сипавсь білий зорепад,
З Чорногори вітер буйний віяв.
І призналась дівчина з Карпат,
Що в любистку коси свої миє.

Приспів.

Не втаю, у серці не втаю,
Що поїхав з гір у рідне місто.
Та мені спокою не дають
Чорні коси, скупані в любистку.

Приспів','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_86256'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_86256','Любисток','Синь Карпатських гір і синь небес,
