INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_86858','Гуцульське весілля','Слова: Марія Влад','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Бубон б''є,
А молода плаче...

Та не шуми, ліщинонько,
Та й не розвивайся,
Не плач, не плач, дівчинонько,
Та не віддавайся.

А скрипка тішиться:
Будем їсти, будем пити...
Бубон не спішить:
Як бог дасть, як бог дасть...

А це що за ґазда,
Що так засмутився,
Гостей не приймає?
Ґаздиня дрімає,
Музика не грає...

Ану, хлопці,— в круг!
І — пішов аркан
В рух
Попід паркан —
У-у-ух!

Легіні плечисті
Завихріли в свисті
Вітром в падолисті,
Крешуть топорами —
Іскри за горами!

А вважай, що прийде:
Раз — сів!
Два — присів!
Не страхайте в будах псів,
Хлопці, глину не місіть,
Не топчіть отав...

А вважай, що прийде:
Тихо — батько спить.
І трава не шелестить.
Та за хвилю:
Батько встав!
І задвірок пеклом став.
Свист і тропіт.
Із чола градом піт.
Не шкодуйте чобіт!
Раз весілля —
То весілля!

Затанцюймо, мила,
Чуєш — коні
На припоні
Рвуть вудила.

Що нам до усіх?
Най собі судачать,
Подаруй сьогодні сміх,
А завтра — най плачу.
Поцілуй мене при всіх —
Най вороги бачать.
Най їм буде гірко.
Бо то пиво, що не пилось,—
На сьогодні згіркло...

А скрипочка впилась — плаче,
Молода сміється.
Гуляй, гуляй, моя доню,
Та й нагуляєшся.
А як прийдеш додомочку
Та й задумаєшся...

В молодички зуби білі,
А очі гарячі.
На гуцульському весіллі
Навіть столи скачуть.

Ой по плаю білі вівці,
По плаю, по плаю.
А я спала з музикантом,
Бігме ся не таю.

А я спала з музикантом —
Захопили зорі.
Та я втекла у долину.
А музика д''горі.

І-іх!..
Кому сміх,
А мене бив чоловік,
Вкоротився б йому вік!

Бив руками, скільки міг,
Ще й сливовим суком
За мій гріх...
(А гріх у міх
Та — буком...)

Ой ти, куме, кумцю милий,-
Ми ся покумали.
Якби ми ся полюбили —
Гріха би не мали.

Та не бий вже, чоловіче,
Бо нічого не є вічне,
Я ж — твоя жінка вінчана,
А хто тебе похоронить,
Як мене скалічиш?..

Трясеться хата,
Реве худоба,
А весілля веселиться
Третю добу.

Може, гості запрошені,
Чимось не вподобав?
Беріть їжте, прошу — пийте,
Веселіться добре.

А ви, бубни, не спіть,
Смійтеся, цимбали.
Нехай буде легіникам
Ніченьки замало...

Так їх вітер носить,
Аж земля гуде.
Бережіться, котрі босі,—
"Гуцулка" іде!..

Я косити густі трави
Не можу ся скласти.
Танцювати на забаві —
Лиш коби допасти.

А хто в горах виростає,
П''є з ріки водиці,
То за тим очима водять
Дівки й молодиці.

Там бесіда люба йтиме,
Де ми самі двоє...
Відступися, побратиме,
Це — дівчина моя.

Твоя?.. Моя!..
Ще побачимо — чия!
І — за топірці.
Блискавки в руці.

Дівчинонько молоденька,
Ти — велика зрада.
Якби мене порубали —
Ти би була рада.

Хто їсть, хто п''є,
Що на столах є.
А скрипка серце крає,
Щосили бубон б''є.

Ой цимбали,
Срібні цимбали —
Невгомонні води Черемоша!
Виводите дрібно
Мелодії рідні —
На місці встояти не можна.

Та най собі загуляю,
Поки молоденька,
Поки в горі Чорногорі
Вода студененька.

На високій полонині
Вбив половик каню.
А то уже — по весіллю,
Та й по видриганню.

Розходяться гості.
Скрипка жалібно
На помості
Кигиче:
Не їла, не пила я...
А бубон, звично,
Як завше:
Я казав,
А казав же...

Заграй ще разок маленький
Легіням, музико.
Ой дівчина молоденька —
Забава велика!

Ой забава, що забава,
То на цілі гори!
Лиш молода ще не знала —
На щастя чи горе...','[''pisni.org.ua'', ''cat:kolomyyky'', ''cat:vesilni'', ''cat:zhartivlyvi'', ''Коломийки'', ''Весільні пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_86858'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_86858','Гуцульське весілля','Бубон б''є,
А молода плаче...

Та не шуми, ліщинонько,
Та й не розвивайся,
Не плач, не плач, дівчинонько,
Та не віддавайся.

А скрипка тішиться:
Будем їсти, будем пити...
Бубон не спішить:
Як бог дасть, як бог дасть...

А це що за ґазда,
Що так засмутився,
Гостей не приймає?
Ґаздиня дрімає,
Музика не грає...

Ану, хлопці,— в круг!
І — пішов аркан
В рух
Попід паркан —
У-у-ух!

Легіні плечисті
Завихріли в свисті
Вітром в падолисті,
Крешуть топорами —
Іскри за горами!

А вважай, що прийде:
Раз — сів!
Два — присів!
Не страхайте в будах псів,
Хлопці, глину не місіть,
Не топчіть отав...

А вважай, що прийде:
Тихо — батько спить.
І трава не шелестить.
Та за хвилю:
Батько встав!
І задвірок пеклом став.
Свист і тропіт.
Із чола градом піт.
Не шкодуйте чобіт!
Раз весілля —
То весілля!

Затанцюймо, мила,
Чуєш — коні
На припоні
Рвуть вудила.

Що нам до усіх?
Най собі судачать,
Подаруй сьогодні сміх,
А завтра — най плачу.
Поцілуй мене при всіх —
Най вороги бачать.
Най їм буде гірко.
Бо то пиво, що не пилось,—
На сьогодні згіркло...

А скрипочка впилась — плаче,
Молода сміється.
Гуляй, гуляй, моя доню,
Та й нагуляєшся.
А як прийдеш додомочку
Та й задумаєшся...

В молодички зуби білі,
А очі гарячі.
На гуцульському весіллі
Навіть столи скачуть.

Ой по плаю білі вівці,
По плаю, по плаю.
А я спала з музикантом,
Бігме ся не таю.

А я спала з музикантом —
Захопили зорі.
Та я втекла у долину.
А музика д''горі.

І-іх!..
Кому сміх,
А мене бив чоловік,
Вкоротився б йому вік!

Бив руками, скільки міг,
Ще й сливовим суком
За мій гріх...
(А гріх у міх
Та — буком...)

