INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_86575','Летять галочки у три рядочки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Бібліотека поета. Народна Лірика. 2. Перлини української народної пісні. Упорядник В. М. Гордійчук. - К.: Музична Україна, 1989. - 392 с.','Весільні — Свята Неділя: Розплітання Коси. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... Мед і Ябка... Рай розвився Господь звеселився. А жаль же мені Русої Коси і Панянської Краси. Да летять Галочки да у Три Рядочки Летять Галочки у Три Рядочки Ой дай Мати Гребінку. Розчисати Русу Косу у Дівки. Івана Купала тай в Воду упала. Під Калиною Дівчина там Косу Русу чесала. Листки з приводу цієї Пісні: Весілля — Свята Неділя: Дари. Пов''язування. Коса. Про Свято Івана Купала Стежки до листків про Українські традиції.','Летять Галочки у Три рядочки   |
