INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_866116','Де ти, хмелю, зиму зимував','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Россія. Полное географическое описание Нашого Отечества. Отделъ ІІ - Населеніе, гл. V -Пинчуки.',NULL,'Де ти, хмелю, зиму зимував, що не розпускався?
Де ти, сину, ноч ночував, що не розувався?
— Зимував я, зимовав в лузі на тичині,
Ночував я, ночував в славної дівчини.
—Нехороше, синку, робиш, що по ночі ходиш:
Скаржилися молодиці, що ти шкоду робиш.
— Ох, робив я, моя матко, і буду робити:
Було мене, моя матко, у сім літ оженити.
— Ой я ж тебе, мой синочку, дай не боронила;
Було тобі оженитись, скоро я родила.','[''pisni.org.ua'', ''cat:poliski'', ''Пісні з Полісся'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_866116'), datetime('now')),datetime('now'));
