INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_869878','Колискова','Музика: Олександр Білаш Слова: Дмитро Павличко. Виконує: Лариса Остапенко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ніч гойдається мов дим,
Мерехтить зоря в блакиті,
Мохом тиші золотим
Кам''яні шляхи накриті.

Приспів:
Спи, моя дитино, спи,
Стану я сама зорею,
Нахилюся від журби
Над планетою твоєю...

Світ на променях своїх
До спочинку заколишу,
Щоб ніхто стоптать не міг
На землі вечірню тишу.

Приспів.

Ніч гойдається мов дим,
Мерехтить зоря в блакиті,
Мохом тиші золотим
Кам''яні шляхи накриті.

Приспів.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_869878'), datetime('now')),datetime('now'));
