INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87013','Чудовий сон','Музика: Богдан Весоловський Слова: Богдан Весоловський','uk','ukraine_1991',NULL,NULL,'Богдан Весоловський "Прийде ще час..." Львів "Галицька видавнича спілка" 2001',NULL,'Хоч багато вже років минуло
З того часу, як ми розійшлись,
А всі наші найкращі надії
Рознесли буревії кудись...

Хоч між нами безкраї простори,
Хоч нас ділить невблаганний час,
Думи линуть до тебе за море,
Де життя усміхалось до нас...

Чудовий сон минулих днів
У серці перлами горить,
Таємним шляхом журавлів
До тебе спогад мій летить.

Летить туди, де у житах
Волошки й мак цвіли,
Де на розспіваних полях
Любов і щастя ми знайшли.','[''pisni.org.ua'', ''cat:dances'', ''cat:tango'', ''Пісні до танцю'', ''Танґо'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_87013'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_87013','Чудовий сон','Хоч багато вже років минуло
З того часу, як ми розійшлись,
А всі наші найкращі надії
Рознесли буревії кудись...

Хоч між нами безкраї простори,
Хоч нас ділить невблаганний час,
Думи линуть до тебе за море,
Де життя усміхалось до нас...

Чудовий сон минулих днів
У серці перлами горить,
Таємним шляхом журавлів
До тебе спогад мій летить.

Летить туди, де у житах
Волошки й мак цвіли,
Де на розспіваних полях
Любов і щастя ми знайшли.');
