INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_870450','У тій Америці','Українська народна пісня. Виконує: Світозари','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У тій Америці сипана дражочка,
Ходить по ній, ходить моя фраїрочка.
Ходить, ходить, ручки заламує,      |
Же їй милий до краю рукує,          |
Же їй милий до краю рукує.          | (2)

Не плач, мила, не плач,
Та то вшистко дармо,
Бо я вже рукую, скоро ютро рано.
Прийшов я там до Нев-Йорку вночі,   |
Заплакали мої сиві очі,             |
Заплакали мої сиві очі.             | (2)

Ой Боже ж, мій Боже,
Як си тяжко старам.
Я на тоту шифу, сідати на ню мaм?
Бо на шифі попи не ховают,          |
Лем матроси до моря руцають,        |
Лем матроси до моря руцають.        | (2)

Ходить, ходить, ручки заламує,      |
Же їй милий до краю рукує,          |
Же їй милий до краю рукує.          | (2)','[''pisni.org.ua'', ''cat:emigration'', ''cat:lemkivski'', ''Пісні про еміґрацію'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_870450'), datetime('now')),datetime('now'));
