INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_866714','Не питай','Музика: невідомий Слова: Іван Огієнко','uk','ukraine_before_1917',NULL,NULL,'Струни серця. Українські народні пісні про кохання. Київ, Держлітвидав, 1969.',NULL,'Не питай,
Чого в мене заплакані очі,
Чого часто тікаю я в гай
І блукаю я там до півночі,
Не питай, не питай, не питай.

Не питай,
Чого в''яну і сохну, як квітка,
Бо так щиро кохаю тебе,
Ти покинув мене, сиротину,
На посміх, поговір для людей.

Не питай,
Бо нічого тобі не скажу я, -
Бачив ти мої сльози і сум,
А нещирі слова та байдужі
Не розвіють тяжких моїх дум','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_866714'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_866714','Не питай','Не питай,
Чого в мене заплакані очі,
Чого часто тікаю я в гай
І блукаю я там до півночі,
Не питай, не питай, не питай.

Не питай,
Чого в''яну і сохну, як квітка,
Бо так щиро кохаю тебе,
Ти покинув мене, сиротину,
На посміх, поговір для людей.

Не питай,
Бо нічого тобі не скажу я, -
Бачив ти мої сльози і сум,
А нещирі слова та байдужі
Не розвіють тяжких моїх дум');
