INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_872116','Сонце заходить, гори чорніють','Музика: Олексій Керекеша Слова: Тарас Шевченко. Виконує: Олексій Керекеша','uk','ukraine_before_1917',NULL,NULL,'http://www.realmusic.ru/ok1band/',NULL,'Сонце заходить, гори чорніють
Пташечка тихне, поле німіє.
Радіють люди, що одпочинуть,
А я дивлюся і серцем лину
В темний садочок на Україну.

Лину я, лину, думку гадаю,
І ніби серце одпочиває
Чорніє поле, і гай, і гори,
На синє небо виходить зоря  | (2)

Ой зоре! - і сльози кануть
Чи зійшла вже на Україні?
Чи очі карі шукають
На небі синім? Чи забувають?

Коли ж забули, бодай заснули,
Про мою доленьку щоб і не чули.','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_872116'), datetime('now')),datetime('now'));
