INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_86705','Жито, мамцю!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика.',NULL,'Жито, мамцю, жито, мамцю,
Жито - не полова...
Як дівчину не любити,
Коли чорноброва!

Жито, мамцю, жито, мамцю,
Жито - не пшениця...
Як дівчину не любити,
Коли чепуриться!

Жито, мамцю, жито, мамцю,
Жито - колосочки...
Як дівчину не любити,
Коли чорні очки!    Фонограма-мінус (mp3, 192 kbps). весільна полька','[''pisni.org.ua'', ''cat:dances'', ''cat:polky'', ''Пісні до танцю'', ''Польки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_86705'), datetime('now')),datetime('now'));
