INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_870312','Америцький край',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис','альбом "Отчий дім"','Полетів бим на край світа,
Як тот вітер в полі літа,
Гей, в америцький край.
Лем жаль ми тя, моя хижо,   |
Лем жаль ми тя, моя хижо,   |
Солом''яная жаль.            | (2)

Ой жаль ми вас, вівці сиві,
Шом плекав вас без три зими,
Гей, який ми вас жаль,
Бо іначе бим поїхав,        |
Бо іначе бим поїхав,        |
В америцький край.          | (2)

Ой жаль ми тя, моя страно,
Де жиют мамичка з няньом
Гей,  який ми вас жаль.
Хоч бідую - не поїду,       |
Хоч бідую - не поїду,       |
В америцький край.          | (2)

Полетів бим на край світа,
Як тот вітер в полі літа,
Гей, в америцький край.
Лем жаль ми тя, моя хижо,   |
Лем жаль ми тя, моя хижо,   |
Солом''яная жаль.            | (2)

варіант пятого стовпчика:

Не покину рідну землю,
Тут сказав я вперше неню,
Гей,мамо рідная...
Тут зробив я перші кроки,
тут пройшли юнацькі роки,
молоді літа.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_870312'), datetime('now')),datetime('now'));
