INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87001','Подай рученьку','Музика: Богдан Весоловський Слова: Богдан Весоловський. Виконує: Лілія Коструба','uk','ukraine_1991',NULL,NULL,'Богдан Весоловський "Прийде ще час..." Львів "Галицька видавнича спілка" 2001',NULL,'Світив нам місяць ясний
І зорі над ставом,
Як ти сказала: "Любий,
Нам не одним шляхом",

Але хоч підеш в новий, незнаний світ,
Тужити завжди будеш
За щастям давніх літ.

Подай рученьку і до серденька пригорни,
Колишні мрії й кохання приверни,
Щоб промінь щастя ніколи нам не гас,
Бо вже ніщо на світі не розлучить нас.','[''pisni.org.ua'', ''cat:dances'', ''cat:tango'', ''Пісні до танцю'', ''Танґо'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_87001'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_87001','Подай рученьку','Світив нам місяць ясний
І зорі над ставом,
Як ти сказала: "Любий,
Нам не одним шляхом",

Але хоч підеш в новий, незнаний світ,
Тужити завжди будеш
За щастям давніх літ.

Подай рученьку і до серденька пригорни,
Колишні мрії й кохання приверни,
Щоб промінь щастя ніколи нам не гас,
Бо вже ніщо на світі не розлучить нас.');
