INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_867307','Ой зацвіла рожа край вікна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Народні перлини. Українські народні пісні. Київ, Державне видавництво художньої літератури, 1961.',NULL,'Ой зацвіла рожа край вікна... | (2)
Ой мала я мужа,
Ой мужа я мала,
Ой мала я мужa
Пияка.

Нічого не робить, тільки п''є, | (2)
Як прийде додому,
Як додому прийде,
Як прийде додому,
Жінку б''є.

"Не бий мене, муже, не карай, | (2)
Бо покину діти,
Бо покину дрібні,
А сама поїду
За Дунай!"

Ой як я на лодку сідала, | (2)
Правою ручкою,
А білим платочком,
А білим платочком
Махала.

"Ой вернися, жінко, додому, | (2)
Бо горшки не миті,
І миски побиті,
Горе ж мені жити
Самому!"

Ой як я вернулась додому, | (2)
І горшки побиті,
І миски не миті,
Ой, а діти плачуть,
Їсти хтять','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_867307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_867307','Ой зацвіла рожа край вікна','Ой зацвіла рожа край вікна... | (2)
Ой мала я мужа,
Ой мужа я мала,
Ой мала я мужa
Пияка.

Нічого не робить, тільки п''є, | (2)
Як прийде додому,
Як додому прийде,
Як прийде додому,
Жінку б''є.

"Не бий мене, муже, не карай, | (2)
Бо покину діти,
Бо покину дрібні,
А сама поїду
За Дунай!"

Ой як я на лодку сідала, | (2)
Правою ручкою,
А білим платочком,
А білим платочком
Махала.

"Ой вернися, жінко, додому, | (2)
Бо горшки не миті,
І миски побиті,
Горе ж мені жити
Самому!"

Ой як я вернулась додому, | (2)
І горшки побиті,
І миски не миті,
Ой, а діти плачуть,
Їсти хтять');
