INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_871219','Толока','Музика: Ігор Білозір Слова: невідомий. Виконує: Ватра','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Поза крайнім двором,
Під явором-осокором
Хлопці та дівчата
Столочили толоку -
Танці-вириванці,        |
До світанку співи хором |
Про любов зрадливу,     |
Про недоленьку гірку.   | (2)

Приспів:
Толока, толока,
Витина гопака.
Гомінка, гомінка -
Отака толока.

А в суботу рано
На подвір''я удовине
Сходилися люди
І творили дивну річ:
Жито із соломи,         |
Воду із святої глини -  |
Виростала хата          |
І співала цілу ніч.     | (2)

Приспів.

Як то добре мати
Мудру донцю під рукою,
Я віднині знаю
І не треба словника,
Що колись суботник      |
Називали толокою,       |
Ну і дискотеку          |
Називають толока.       | (2)

Приспів. (2)','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_871219'), datetime('now')),datetime('now'));
