INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_872415','Непорушна дружба','(Дума про возз’єднання України з Росією)','uk','ukr_ssr_1919_1991',NULL,'1982','"Думи. Історико-героїчний цикл". Київ, Дніпро, 1982.','Ген-ген на полях, / На колгоспних ланах, Де могили предковічні з вітрами розмовляють, Там нащадки козацькі шляхи в новий світ прокладають, Шляхи до комунізму торують, / Своє життя будують З російським народом / У єднанні, у згоді! ― Див. також "Отрадный результат нашего движения к коммунистическому обществу". Комуністичні конструкції історико-героїчного циклу українських народних дум. Конструкція О. Дея, 1982: Думи. Історико-героїчний цикл." Київ, Дніпро, 1982. ВСТУПНЕ СЛОВО. (МИХАЙЛО СТЕЛЬМАХ) ПРИМІТКИ. (Олексій Дей) Дума ― віршований твір, що не має строфічної будови, як, скажімо, пісня. Її різноскладні рядки діляться не на строфи, а на завершені, іноді досить довгі періоди. Рядки думи здебільш об''єднані дієслівною римою. Виконується дума мелодійним речитативом, що час од часу переходить у співучий малюнок, в супроводі кобзи чи бандури. Перший збірник, в якому було вміщено дев''ять дум, вийшов у 1819 році (Цертелєв М. Опыт собрания старинных малороссийских песней). Збірник складає основну масу творів українського народного епосу історико-героїчного змісту.:-) Більшість дум записано від кобзарів та лірників у різних, часом сюжетно віддалених варіантах. До книжки відібрано по одному, в окремих випадках — по два варіанти кожної думи історико-героїчного циклу українського народного епосу. Тут представлені найяскравіші з ідейно-художнього боку зразки дум від найдавніших записів до записів радянського часу.:-) Публікація текстів здійснена за першоджерелами — першодруком або збереженим у архівах рукописом записувача. Враховуючи популярний характер видання, тексти подаються за сучасним правописом із повним відтворенням лексичного складу та синтаксичного ладу оригіналу, але з певною уніфікацією вимови з метою наближення її до сучасних літературних норм. Зокрема, не зберігаються зафіксовані записувачами дифтонги; тверда вимова закінчень дієслів третьої особи; тверді закінчення прикметників у множині; діалектна вимова ненаголошених голосних, відмінна від літературної; форми з діалектними пом''якшеннями або ствердіннями приголосних; фонетична передача префіксів та суфіксів тощо. Виняток тут становлять римовані слова, випадки, обумовлені милозвуччям, а також лексика, типова для тогочасної живої мови, яка відображає її колорит (напр., прапірок, праперки, шклянка, хмель, хліб-соль, жоночий, шкарби, штити, пошов, трапезонтський, єго, своєго та ін.). З тією ж метою — відтворення мовного колориту кобзарського співу — не уніфікуються такі паралельні форми, як: Озів — Азов, Базавлук — Базавлуг, Килимський — Килиїмський, многії літа — многая літа, сребраники — срібляники, кролев-ський — королевський, тогді — тоді, міжду — между та ін. Такі форми є органічною ознакою стилю дум, для якого властива піднесеність, урочистість, надзвичайність, чого кобзарі й лірники прагнули досягти навмисним введенням:-)) до мови дум русизмів,:-)церковнослов''янізмів та зрідка — полонізмів. Поданий у виданні коментар дасть можливість читачам розширити відомості про кожну думу, про багатство та популярність:-) українського народного епосу в цілому. При підготовці текстів упорядник враховував досвід своїх попередників — видавців дум окремими збірниками: Ф. Колесса.:-) Українські народні думи. Львів, "Просвіта", 1920; зб. "Українські народні думи та історичні пісні. Упорядкували: П. Д. Павлій, М. С. Родіна, М. П. Стельмах.—К., Вид-во АН УРСР, 1955; зб. Думи. Упорядкував М. П. Стельмах.— К., Держлітвидав України, 1959; зб. Думи. Упорядкування Г. А. Нудьги.—К., "Радянський письменник", 1969; зб. Украинские народные думы. Издание подготовил Б. П. Кирдан.— М., "Наука", 1972. (Далі при посиланні на ці видання зазначаємо лише рік і сторінку). "ОЙ ПОЛЕМ, ПОЛЕМ КИЛИЇМСЬКИМ..." Розділ охоплює думи, які в широких епічних картинах змальовують багатовікову боротьбу проти турецько-султанських і татарсько-ханських нападників, з глибокою емоційністю відтворюють відданість своїй батьківщині оборонців рідної землі. Провідними темами цих дум є: а) бойові подвиги, дружба, побратимство й вірність захисників вітчизни; б) героїчне звільнення від турецько-татарської неволі й каторги. Виняткової сили емоційного впливу досягли кобзарі при розкритті другої теми в формі плачу невільників. Козак нетяга КОЗАК НЕТЯГА. Записано в кінці XVII ст. (Дума дійшла до нас завдяки рукописному збірнику Кондрацького, датованому 1684 р.). Вперше думу опублікував відомий вчений М. Возняк у 1928 р.:-) Друкується за виданням: Украинские народные думы. 1972, с. 71—72. Килиїмське поле — місцевість біля міста Кілії (за народною вимовою — Килия), розміщеного на Кілійському рукаві р. Дунай, захопленого турками і перетвореного ними в фортецю. Тепер К і л і я — районний центр Одеської області. Козак запоровський — неточно зроблений записувачем вислів: "козак запорозький". Козак Голота КОЗАК ГОЛОТА. Записано в 1854 р. від лірника А. Никоненка в с. Оржиці, Лубенського повіту, на Полтавщині. Вперше надруковано в зб.: Записки о Южной Руси, т. I. СПб., 1856, с. 14—19. Подається за першодруком. Це один із ширших варіантів думи, головним героєм:-) яких є козак Голота. Дума про козака Голоту записана в шести варіантах. У збірному образі козака Голоти (нетяги, летяги) втілені:-)) кмітливість, мужність, оптимізм і сила рядового козацтва. Гординський шлях — дорога через територію, що контролювалась і була під владою Орди (Гординське поле). Очевидно, і назва походить від слова "орда", що в деяких місцевостях вимовлялось як "горда")....А третя й на хлів незгожа.— "Уже й закинуть не способна",— пояснював співак, тобто нею й дірки в стрісі не прикрити. Січ — осередок українського козацтва, де воно організовувалось як військова сила протягом XVI—XVIII ст. (до 1775 р., коли Запорозька Січ перестала існувати:-). Січ була опорою українського народу в боротьбі проти феодально-кріпосницького гніту та іноземних загарбників. Спершу Запорозька Січ знаходилась на острові Токмаківка в нижній течії Дніпра, з кінця XVI до початку XVIII ст.— на острові Базавлук (Чортомлик). Смерть Корецького (фальсифікат: "нар. дума") СМЕРТЬ КОРЕЦЬКОГО. Текст думи зберігся у збірнику Кондрацького (1684 р.). Опублікував її М. Возняк 1929:-) ("Україна":-), 1929), № 3—4). Друкується за виданням: зб. Думи. 1969, с 48—51. Цецора — село поблизу Ясс в Румунії, відоме поразкою польсько-шляхетського війська в битві з турецько-татарськими військами в 1620—1621 рр. Під час бою тут загинув М. Хмельницький, батько Богдана Хмельницького, а останній потрапив у полон. Царгород, Царград — давня слов''янська назва Стамбула, кількавікової столиці Туреччини і великого торгового міста, де в XV—XVII ст. вівся продаж захоплених у полон невільників. Корець — містечко на Новоград-Волинщині. Межиріччя — населений пункт на Волині. Отаман Матяш старий ОТАМАН МАТЯШ СТАРИЙ. Відомий єдиний:-)) запис думи, опублікований П. Житецьким за рукописом "Повести малороссийские числом 16. Списаны из уст слепца Ивана, лучшего рапсодия, которого застал я в Малороссии в начале XIX в." в кн.: Мысли о народных малорусских думах. К., 1893, с. 238—240. Подається за першодруком. Одна з копій "Повестей" позначена 1805 р. Записувач дум надав ряду слів російських:-) форм, що в даній книзі не відтворюється:-)), проте лексика зберігається повністю. В третьому від кінця рядку в дужках подано нерозбірливо написане слово, яке П. Житецький прочитав як "лицаря да". Образ отамана Матяша — збірний, епічний. Його, як досвідченого старого воїна, дума протиставляє легковажній необстріляній молоді — бравославцям-небувальцям. Словом "бравославці" тут означено молодих козаків, що хизувалися своїм становищем, красувалися (бравий — гарний, красивий) козацькою славою, хоч ще й не мали для цього достатніх підстав. Устя Самари — Богу— йдеться про місцевість, де впадає річка Савранка (за народною вимовою — Самарка) в Південний Буг. Семенів козацький ріг— один із півостровів у Південно-Бузькому лимані поблизу Дніпровського лиману. Кайнарська долина — існує думка, що назва відноситься до низини при впадінні річки Савранки в Південний Буг. Проте є назва річки Кайнара, яка впадає в р. Реут, притоку Дністра. Отаман Матяш... // Шість тисяч турок-яничар побіждав...— епічний прийом гіперболи, яким народна творчість характеризує воїна-богатиря, лицаря.:-) Федір безродний, бездольний ФЕДІР БЕЗРОДНИЙ, БЕЗДОЛЬНИЙ. Записав 1873 р. М. Лисенко від кобзаря О. Вересая з с. Калюжниці, Прилуцького повіту, Полтавської губернії. Вперше надруковано в "Записках Юго-Западного отдела ИРГО за 1873 г.", т. I. К., 1874, додаток "Ноты к думам и песням, исполняемым О. Вересаем". Подається за першодруком. Від різних кобзарів протягом 1805—1900-х рр. записано дев''ять варіантів цієї думи, одні з яких змальовують смерть Федора Безродного в бою, інші — від несподіваного нападу "безбожних ушкалів", тобто турецьких яничарів, на нього і джуру, коли вони "понад сагою Дніпровою" "обід обідали". Федор безродный — епічний персонаж дум....много війська... через мечу положено — багато війська загинуло від меча в бою. Військо дніпрове — тобто козацьке військо, запорозькі козаки. Базалуг — йдеться про Базавлук, праву притоку Дніпра поблизу м. Чортомлика (нині — в районі м. Нікополя), а також острів під тією ж назвою в місці впадіння притоки в Дніпро. Самарські брати САМАРСЬКІ БРАТИ. Записав 1908 р. на фонограф Ф. Колесса від кобзаря М. Кравченка з с Великих Сорочинців, Миргородського повіту, Полтавської губернії, і опублікував у виданні: Українські народні думи, 1920, с 98—100. Подається за першодруком. В думі знайшла відображення ідея покарання за порушення усталених традицій (в даному разі — самовільний вступ до охотного — добровільного — війська всіх трьох братів, що суперечило звичаю: один повинен був лишитися на господарстві; зневажання благословення батьків, порушення забобонного релігійного марновірства:-)), характерного для пригнічених мас:-)) феодальної доби:-). Дума відома в десяти записах, найдавніший із яких — 1805 р., а найновіший — 1930-го. Всі варіанти близькі сюжетами. Криниця Салтанка — джерело на березі річки Салтанки. Не єсть то нас куля яничарська постріляла, // А єсть то нас та й отцева молитва покарала — відгомони язичницької віри:-)) в магічну дію:-) слова, що вилилася в форму:-)) християнсько-релігійної моралістичності:-). Смерть козака на Кодині-долині СМЕРТЬ КОЗАКА НА КОДИНІ-ДОЛИНІ. Записано від кобзаря:-)в м. Сенчі, Лохвицького повіту, на Полтавщині. Друкується за автографом. (Архів Географічного товариства СРСР у м. Ленінграді, ф. 31, опис 1, од. зб. 25, с 97—100). Кодима (Кодина) — права притока Південного Бугу. Плач невольника ПЛАЧ НЕВОЛЬНИКА. Записано на початку 1830-х рр. у Полтавській губернії.:-) Опубліковано у виданні: Малорусские и червонорусские народные думы и песни. СПб, 1836, с. 64—65. Подається за першодруком. Дума відома в кількох записах. Пристань Козловська — пристань у місті Козлові, нинішня назва — Євпаторія. Плач невольників ПЛАЧ НЕВОЛЬНИКІВ. Записано в 1850-х рр. в м. Вільшана, Богодухівського повіту, на Харківщині, від кобзаря П. Колибаби. Вперше надруковано в кн.: Исторические песни малорусского народа с объяснениями Вл. Антоновича и М. Драгоманова, т. I. К., 1874, с. 90. Подається за першодруком. Невольники на каторзі НЕВОЛЬНИКИ НА КАТОРЗІ. Записав М. Лисенко 1903 р. від О. Сластіона:-), який вивчив думу в 1870-х рр. від кобзаря з Полтавщини.:-)) Вперше надруковано в ж. "Народна творчість та етнографія", 1964,:-)№ 4, с 76—78 (з мелодією). Друкується за автографом. Невільницький цикл дум нараховує близько 20 варіантів, які, розходячись сюжетно, в сукупності яскраво змальовують тяжку біду козаків, що попадали в турецький полон, і тисяч людей, захоплених татарсько-турецькими наїзниками в ясир. З винятковою емоційністю в них висловлена туга за батьківщиною, протест проти загарбників та прагнення до свободи. Маруся Богуславка МАРУСЯ БОГУСЛАВКА. Записав Ф. Колесса 1908 р. в м. Миргороді на Полтавщині від кобзаря М. Кравченка. Друкується за виданням: Ф. М. Колесса. Мелодії українських народних дум. К, 1969, є. 270—272 (мелодія — на с.','Гей, що на нашій славній Україні
Та були суворі години:
Що тими несходимими степами
Та тими битими ординськими шляхами,
Селами, городами,
Зеленими хуторами,
Ой да то ж то не тільки слава козацька гуляла,
А й ріками-потоками
Людські сльози-горе розливались!..

Налітали чорні круки на Україну —
Її діти боронили до загину,
Покривали вражим трупом поле...
Ой ти доле наша, доле!
Тільки степ широкий устелили
Високії без числа могили...

А як шляхта скрізь запанувала,
Невільницею Україна стала,
Горя зазнала,
Слізьми обливалась,
На вольную воленьку сподівалась!

Гей, як з''явився тоді на Січі Хмельницький,
Богдан-Зиновій, Сотник чигиринський,
Козаків єднав,
Народ закликав
До боротьби нещадної,
До перемоги славної
Над панами лютими,
Хижаками неситими!

Гей, то ж не вітри буйнії дуби нагинали,
На Дніпрі-Славуті хвилі-гори підіймали,—
То хвиля народного гніву здіймалась.
Серця гартувала,
Помстою наливала!

То ж то козацькеє військо,
Славне Запорозьке,
Тією помстою-гнівом палало,
В похід на панів виступало
Волю здобувати,
Людей з панського ярма визволяти!

А за тими козаками
Незліченними полками
Простий люд — посполиті селяни
Прибувають до Богдана:

Максим Перебийніс веде військо з Поділля,
А Іван Богун з Подністров''я,
Мартин Пушкаренко з Полтавщини,
А Морозенко з Джалалієм з Брацлавщини,
Іван Кречовський з Київщини,
А Данило Нечай з Вінниччини!

А за ними прилучани й ніженці,
Фастовці й черніговці,
Уманці й білоцерківці
Ще й самого Богдана чигиринці!

Піднялася всенародная сила,
Бо терпіти наруги панської було вже несила!
Гей, хоч недорогі на війську козацькому шати,
Та серця людські правдою й гнівом багаті!
Всі добре знали,
Що в нещадну боротьбу вступали
Та велику віру в перемогу мали!

Ой та то ж то не рік і не два
Точилася та жорстока боротьба!
Вірні сини України вкрили себе славою
Під Корсунем і Пилявою!
Загнали ляшків, Загнали панків
Од Жовтих Вод аж за Віслу,
Щоб більше на Україну не лізли!

Гей, тоді ж то бачить Богдан,
Бачить гетьман,
Що пани Потоцькі
Та магнати Конецпольські
Знову своїх недобитків збирають,
Свою думку мають —
Іти Хмельницького воювати,
Народ український у панське ярмо повертати,

То й бачить Богдан,
Бачить гетьман,
Що тоді буде над шляхтою перемога,
Як прийде від російського брата рідна допомога!
Гей, та тоді ж то Хмельницький,
Гетьман український,
Скликає у Переяславі раду —
Козацьку громаду!
Громаду скликає,
Гостей закликає —
Рідного російського брата —
До нашої хати.

Тоді ж то в Переяславі
В усі дзвони дзвонили,
А люди між собою гомоніли,
Раду радили
Всією громадою:
"Ніде нам, браття,
Кращої долі-щастя шукати,
Як у єднанні з російським братом!

Будемо ж ми прохати
Свого єдинокровного брата:
Прийди до нас, рідний брате,
В боротьбі з ворогами помагати!
Та будемо ми спільне життя будувати,
Та будемо в єдиній сім''ї проживати,
Один одному в помочі ставати,
Хліба-солі з упокоєм уживати!"

Отак розмовляли
І клятву велику давали
В єднанні з російським братом жити
І довічно щастя й горе ділити!

Гей, що з тої пори триста років минає,
Таж не горе козацьке,
А наше щастя радянське
На Україні цвітом весняним буяє
І кремлівська зоря його осяває!

Ген-ген на полях,
На колгоспних ланах,
Де могили предковічні з вітрами розмовляють,
Там нащадки козацькі шляхи в новий світ прокладають,
Шляхи до комунізму торують,
Своє життя будують
З російським народом
У єднанні, у згоді!

Гей, гей, від Переяслава і донині
У сім''ї єдиній
Живе народ український з російським братом
В нашій єдиній хаті!
І цього єднання
Нікому не зламати,
Бо одна в нас мати
І одна ми родина —
Радянська Вітчизна єдина,
Ще й ленінська партія велика!
Від нині довіку!','[''pisni.org.ua'', ''cat:dumy'', ''Думи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_872415'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_872415','Непорушна дружба','Гей, що на нашій славній Україні
Та були суворі години:
Що тими несходимими степами
Та тими битими ординськими шляхами,
Селами, городами,
Зеленими хуторами,
Ой да то ж то не тільки слава козацька гуляла,
А й ріками-потоками
Людські сльози-горе розливались!..

Налітали чорні круки на Україну —
Її діти боронили до загину,
Покривали вражим трупом поле...
Ой ти доле наша, доле!
Тільки степ широкий устелили
Високії без числа могили...

А як шляхта скрізь запанувала,
Невільницею Україна стала,
Горя зазнала,
Слізьми обливалась,
На вольную воленьку сподівалась!

Гей, як з''явився тоді на Січі Хмельницький,
Богдан-Зиновій, Сотник чигиринський,
Козаків єднав,
Народ закликав
До боротьби нещадної,
До перемоги славної
Над панами лютими,
Хижаками неситими!

Гей, то ж не вітри буйнії дуби нагинали,
На Дніпрі-Славуті хвилі-гори підіймали,—
То хвиля народного гніву здіймалась.
Серця гартувала,
Помстою наливала!

То ж то козацькеє військо,
Славне Запорозьке,
Тією помстою-гнівом палало,
В похід на панів виступало
Волю здобувати,
Людей з панського ярма визволяти!

А за тими козаками
Незліченними полками
Простий люд — посполиті селяни
Прибувають до Богдана:

Максим Перебийніс веде військо з Поділля,
А Іван Богун з Подністров''я,
Мартин Пушкаренко з Полтавщини,
