INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_873756','Коли я стану президентом','Музика: Павло Зібров Слова: Юрій Рибчинський. Виконує: Павло Зібров','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Коли я стану президентом,
Тоді я, мабуть, кину пить,
І буду дітям аліменти
Усім, без винятку, платить!
Бабусям я зроблю презенти
Магнітофони JVC,
Коли я стану президентом,
Мене кохатимуть усі!

Приспів:
Голосуй, голосуй,
Будь, активним, не пасуй  | (2)
Голосуй,
Голосуй, голосуй,
Бюлетені в урни суй       | (2)
Голосуй.

Коли я стану президентом,
Мені простять усі борги,
Казати будуть компліменти
Мої закляті вороги!
Призначу жінку референтом
В питаннях сексу на селі,
І кримінальні елементі
Мені подарять "Жигулі".

Приспів.

Коли я стану президентом,
Я дам голодним ковбаси,
Зроблю стипендію студентам
Таку, щоб їздили в таксі!
Я відміню усі податки
І дам військовим стільки прав,
Що моїм іменем нащадки
Назвуть великий пароплав!

Приспів.

Коли я стану президентом,
Я зранку буду в теніс грать.
Дозволю всім собакам гавкать,
А божевільним страйкувать.
Жлобам і всім інтелігентам
Скажу: "Народ - одна сім''я!"
Коли я стану президентом,
Багатим будеш ти і я.

Приспів. (2)

Коли я стану президентом...','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_873756'), datetime('now')),datetime('now'));
