INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_874052','Вони такі не просто так!','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_1991',NULL,NULL,NULL,'Збірка пісень "КОРАБЛИК"','Ось і не має вже пори,
Пори, що зветься листопадом
І темно-сірі кольори
Застигли, як перед парадом.

Приспів:
Вони такі не просто так,
Вони про щось, напевно, знають,
Вони чекають снігопад
І з нами мовчки розмовляють.

Лежить давно вже на землі
Опале листя закутками,
Дерева, наче, у ві сні
Стоять з похмурими гілками.

Приспів.

Шляхи життєві простяглись
Серед пейзажів не привітних,
Тумани з ними розляглись
Молочним цвітом мрій завітних.

Приспів.

Дощі холодні і рясні
Простори сірі поливають,
А потім зранку вітряні
Сніжинки перші прилітають,

Приспів','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_874052'), datetime('now')),datetime('now'));
