INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87611','Вихваляйте гори й доли','Українська народна пісня','uk','ukraine_1991',NULL,'1997','Фольклорні матеріали з отчого краю. Зібрали В.Сокіл та Г.Сокіл.- Львів, 1998','"Коло цирькви ся сходили, брали хоругви. А від цирькви йшли через Плосінь у Маківку і співали. Хто вмів, тот співав. Співали по царині." Зап. В.Сокіл 28 квітня 1997 року у с. Волосянці від Саган Ганни, 1921 року народж., і Сокіл Ярослави, 1953 року народж.','Вихваляйте гори й доли,
Луги, цвіти, ліси, бори,
Найкраснішу на всі Діви,
Чудо дивной Божой сили.

Милим шумом ну ж, потічки,
Та й піснями, любі птички,
Честь віддаймо днесь царици
Непорочні все Дівици.

І скажім ї: О Маріє!
О пречудна Ти леліє!
Най же буде честь і слава,
Творцю Твому, о ласкава!

Ти в любові сонце ясне,
Нею повне серце красне.
Ти нам місяць і зірниця,
Бо вся чиста ти Дівиця.

Ти як рожа, квітка біла,
Що світ пахом наповнила.
Непорочне ти зачата,
А по смерти в небо взята.

Що Ти Богу так милою,
Це покора причиною.
Ця покора учинила,
Що Ти Бога породила!

Пречудесна Діво Мати,
Не давай нам загибати.
Для любови Сина свого
Хорони нас всих від злого.

Дай нам в ласці Божі жити,
Свято нам житя скінчити,
В небі Бога вихваляти,
Вдячну піснь Тобі співати.    комп''ютерне відтворення','[''pisni.org.ua'', ''cat:boykivski'', ''cat:zeleni-svyata'', ''Пісні з Бойківщини'', ''Пісні до Зелених свят'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_87611'), datetime('now')),datetime('now'));
