INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_875256','Ходить Сонко','Українська народна пісня. Виконує: Росава','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ходить сонко по вулиці,
Носить спання в рукавиці,
