INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87909','Бували дні','Музика: Богдан Весоловський Слова: Шад','uk','ukraine_1991',NULL,NULL,'Богдан Весоловський "Прийде ще час..." Львів "Галицька видавнича спілка" 2001',NULL,'Бували дні, п''яніла ти з любови
І незабудки слала у листах.
При зустрічах дивилась так чудово,
Невинний усміх сяяв на устах...

Приспів:
І що ж ти, люба, тому всьому винна?
Твої чуття мінливі, не стійкі,
Твоя любов, як байочка невинна,
Хоч і уста принадливі такі.
І що ж тобі сказати, як розлюбиш?
Крізь плач промовиш: "Іншого люблю"...
Невже чекать аж знову світом знудиш
І нагадаєш про любов мою.

Бували дні чудового кохання.
Ми так цвіли, мов квіти у полях.
Пропало все, заліг туман розстання
І другий хтось повів на інший шлях.

Приспів.','[''pisni.org.ua'', ''cat:dances'', ''cat:tango'', ''Пісні до танцю'', ''Танґо'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_87909'), datetime('now')),datetime('now'));
