INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_880501','Зажурились чорноморці','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. надіслав Ілля Самойлов','Чорноморське козацьке військо — військові формування 18—19 століть. Утворене російським урядом 1787 року з частин Війська вірних козаків, основу якого складали колишні запорожці.','Зажурились чорноморці,
Що ніде прожити.
Оселився вражий москаль,
Виганяє з хати.

Ой, годі вам, чорноморці,
Худобу плодити.
Запрягайте воли в вози,
Їдь на Кубань жити.

Їдуть, їдуть чорноморці,
Та й занози гнуться.
Ой, як глянуть в край родимий,
З очей сльози ллються.

Бодай тобі, Кухаренко,
Так гірко служити,
Як нам бідним чорноморцям
За Кубанню жити.','[''pisni.org.ua'', ''cat:kozacki'', ''cat:kubanski'', ''Козацькі пісні'', ''Кубанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_880501'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_880501','Зажурились чорноморці','Зажурились чорноморці,
Що ніде прожити.
Оселився вражий москаль,
Виганяє з хати.

Ой, годі вам, чорноморці,
Худобу плодити.
Запрягайте воли в вози,
Їдь на Кубань жити.

Їдуть, їдуть чорноморці,
Та й занози гнуться.
Ой, як глянуть в край родимий,
З очей сльози ллються.

Бодай тобі, Кухаренко,
Так гірко служити,
Як нам бідним чорноморцям
За Кубанню жити.');
