INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_880070','А в довгої лози','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано від Євгенії Тондій фольклористки з Вінниччини',NULL,'А в довгої лози
Пасли хлопці кози,
А дівчата козенята
Та й померзли в ноженята.
А в довгої лози
Та й скакали в терен кози.
То угору, то в долину,
То у рожу, то в калину.
То у рожу темнесеньку,
То в калину червонесеньку.
Ой ви, дівки гожі,
Та кидайте тії кози,
В кривім танці походжаймо
Та ніженьки зігріваймо.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:krasa-pryrody'', ''cat:poliski'', ''cat:vesnyanky-hayivky'', ''Дитячі пісні'', ''Пісні про красу природи'', ''Пісні з Полісся'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_880070'), datetime('now')),datetime('now'));
