INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_873909','Ой, у полі','Слова: Є. Марчук','uk','ukraine_1991',NULL,NULL,'1. надіслав Ілля Самойлов',NULL,'Ой, у полі, ой у полі
Зажовтіли буркуни.

Ой, у полі, ой, у полі    |
Заспівали цвіркуни.       | (2)

Річка хвилю присипає,
Місяць на воді тремтить.

Козак дівку обнімає,      |
Каже: вік буду любить.    | (2)

А, як зорі в небі згасли,
Та й скорбілий день настав.

Козаченько по повісткі    |
На чужбину поскакав.      | (2)

Там у горах на чужбині,
На чеченській стороні

Баче в снах він очі сині, |
Баче жовті буркуни.       | (2)','[''pisni.org.ua'', ''cat:kubanski'', ''Кубанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_873909'), datetime('now')),datetime('now'));
