INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87474','Ой на горі огонь горить','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика.',NULL,'Ой на горі огонь горить,
А в долині козак лежить.
Накрив очі китайкою,
Заслугою козацькою.

Що в головах ворон кряче,
А в ніженьках коник плаче.
"Біжи, коню, дорогою,
Степовою, широкою,

Щоб татари не піймали,
Сіделечка не здіймали,
Сіделечка золотого,
З тебе, коня вороного.

Як прибіжиш під ворота,
Стукни-грюкни біля плота.
Вийде сестра - розгнуздає,
Вийде мати - розпитає:

"Ой коню ж мій вороненький,
А де ж мій син молоденький?" -
"Не плач, мати, не журися,
Та вже твій син оженився:

Та взяв собі паняночку -
В чистім полі земляночку".
Та взяв собі дві світилки —
В чистім полі дві горлички.

Та взяв собі два бояри —
В чистім полі два явори".
Ой на горі вогонь горить,
А в долині козак лежить...','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_87474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_87474','Ой на горі огонь горить','Ой на горі огонь горить,
А в долині козак лежить.
Накрив очі китайкою,
Заслугою козацькою.

