INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_876474','Різдвяна','Музика: Влад Пономаренко Слова: Федір Млинченко. Виконує: Віктор Павлік','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У Вифлеємі Син Божий народився,
Радість велика всім людям прийшла.
Той, хто навчить не робити гріха      |
Людям на щастя з''явився.              | (2)

Зірка рідзвяна їх сяйвом осяває,
Промінь господній пролив на небеса.
Радісна звістка на землю зійшла -     |
Сина Господь посилає.                 | (2)

У заповіті, у мудрості господній,
Бог вседержитель вказав людині шлях.
Бог дав нам щастя - у наших серцях    |
Син Божий єдинородний.                | (2)

Радість настала - Син Божий народився,
Світ Вифлеємська осяяла зоря.
Хай наші душі зігріє вона,            |
Нею весь світ освятився.              | (2)

У Вифлеємі Син Божий народився,
Радість велика всім людям прийшла.
Той, хто навчить не робити гріха      |
Людям на щастя з''явився!              | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''cat:kolyadky'', ''Церковні пісні'', ''Пісні на християнську тематику'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_876474'), datetime('now')),datetime('now'));
