INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_880518','А вже літ більш двісті','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. надіслав Ілля Самойлов',NULL,'А вже літ більш двісті,
Як козак в неволі.
Понад Дніпром ходе,
Викликає долю:

- Гей, вийди, доле, із води,
Визволь мене, козаченько, із біди.
- Не вийду, козаче,
Не вийду, соколе.

Ой, рада б я вийти,
Так сама в неволі.
Гей, у неволі, у ярмі,
Під московським караулом у тюрмі.
У тюрмі, в кайданах
Забрата Богданом.

А його самого
Забрали в кайдани.
Гей, ти  Богдане, Богдане,
Нерозумний гетьмане Богдане!
З нарізниць козацьких
Серпи й поробили.

Ще й гострі шаблюки
На ножі змінили.
Гей, ти, козаче, хапай ніж,
Де побачиш вороженька, там и ріж.','[''pisni.org.ua'', ''cat:kozacki'', ''cat:kubanski'', ''Козацькі пісні'', ''Кубанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_880518'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_880518','А вже літ більш двісті','А вже літ більш двісті,
