INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_875272','Колискова','Виконує: Росава','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Моє миле дитятко,
Зійшла в небі зоря
Спи, маленьке хлоп''ятко,
Спи, моє янголя.

В світі доброго і злого
Ти пізнаєш свій шлях,
Спи, чарівний мій друже,
Хай летить сон, як птах.

Твої очі - синії далі
І голівонька ясна,
Хай не відають печалі
Всміхнені твої вуста.

День прийде на зміну ночі,
Світ мінятиметься знов,
Збережи, моє малятко,
Чистоту душі й любов.

Ой леле, лесенько,
Спи, моє малесеньке...','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_875272'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_875272','Колискова','Моє миле дитятко,
Зійшла в небі зоря
Спи, маленьке хлоп''ятко,
Спи, моє янголя.

В світі доброго і злого
Ти пізнаєш свій шлях,
Спи, чарівний мій друже,
Хай летить сон, як птах.

Твої очі - синії далі
І голівонька ясна,
Хай не відають печалі
Всміхнені твої вуста.

День прийде на зміну ночі,
Світ мінятиметься знов,
Збережи, моє малятко,
Чистоту душі й любов.

Ой леле, лесенько,
Спи, моє малесеньке...');
