INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_880052','Селезень','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано від Павла Івановича Ткачука - фольклориста, етнографа з Вінниччини','У давній міфології образ селезня співвідносився з рухом Сонця, а саме з тією порою, коли','Ладуся:
- Селезеню сизий, селезню косатий,
Пусти погуляти.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
Ладуся:
- Я дров наносила -
Ненька гулять не пустила.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
Ладуся:
- Мене ненька била,
Що намисто загубила.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
(З вервечки дівчата перестроюються і роблять ворота,
в які проходять всі дівчата, починаючи з останньої)

Ой плив Селезенько,
Поплив за водою.
Ой льолі, Ладо,
Поплив за водою.
Поплив за водою.
Та бистрою рікою,
Тихою водою.
Ой льолі, Ладо,
Тихою водою.
А Селезенько плив,
Перстенька згубив.
Ой льолі, Ладо,
Перстенька згубив.
Там Ладуся прала,
Перстенька  підняла.
Ой льолі, Ладо,
Перстенька підняла.
Перстенька підняла,
До серденька клала','[''pisni.org.ua'', ''cat:kupalski'', ''cat:podilski'', ''cat:vesnyanky-hayivky'', ''cat:zeleni-svyata'', ''Купальські пісні'', ''Пісні з Поділля'', ''Веснянки та гаївки'', ''Пісні до Зелених свят'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_880052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_880052','Селезень','Ладуся:
- Селезеню сизий, селезню косатий,
Пусти погуляти.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
Ладуся:
- Я дров наносила -
Ненька гулять не пустила.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
Ладуся:
- Мене ненька била,
Що намисто загубила.
Усі:
- Ой льолі, Ладо,
Пусти погуляти!
(З вервечки дівчата перестроюються і роблять ворота,
в які проходять всі дівчата, починаючи з останньої)

Ой плив Селезенько,
Поплив за водою.
Ой льолі, Ладо,
Поплив за водою.
Поплив за водою.
Та бистрою рікою,
Тихою водою.
Ой льолі, Ладо,
Тихою водою.
А Селезенько плив,
Перстенька згубив.
Ой льолі, Ладо,
Перстенька згубив.
Там Ладуся прала,
Перстенька  підняла.
Ой льолі, Ладо,
Перстенька підняла.
Перстенька підняла,
До серденька клала');
