INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_883070','Нічка була темна','Українська народна пісня. Виконує: Не журись!','uk','ukr_ssr_1919_1991',NULL,NULL,'1. http://poetry.uazone.net',NULL,'Нічка була темна,
В селі було тихо.
До села стихенька
Насувалось лихо.

Під''їжджали кати
До кожної хати,
Забирали друзів
За підпільну працю.

Забирали друзів,
Пов''язали руки
І повели селом
До тюрми на муки.

Там три рази на день
Воду їм давали,
А сім разів на день
Нагаями прали.

Висиділи друзі,
Щось півтора року,
Випустили друзів
Слухати вироку.

Вирок прочитали,
На смерть засудили:
Затріщав скоростріл -
Друзі повалились.

Поховали друзів
Під зеленим плотом,
Та й накрили друзів
Гнилим околотом.

Поховаєм друзів
Під зеленим дубом
І накриєм друзів
Золотим Тризубом.

Не одна вже жертва
За Вкраїну впала,
Слава Україні
І Героям слава!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_883070'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_883070','Нічка була темна','Нічка була темна,
В селі було тихо.
До села стихенька
Насувалось лихо.

Під''їжджали кати
До кожної хати,
Забирали друзів
За підпільну працю.

Забирали друзів,
Пов''язали руки
І повели селом
До тюрми на муки.

Там три рази на день
Воду їм давали,
А сім разів на день
Нагаями прали.

Висиділи друзі,
Щось півтора року,
Випустили друзів
Слухати вироку.

Вирок прочитали,
На смерть засудили:
Затріщав скоростріл -
Друзі повалились.

Поховали друзів
Під зеленим плотом,
Та й накрили друзів
Гнилим околотом.

Поховаєм друзів
Під зеленим дубом
І накриєм друзів
Золотим Тризубом.

Не одна вже жертва
За Вкраїну впала,
Слава Україні
І Героям слава!');
