INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_882154','Коло млина яворина *','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1990','1. Пісні УСС на мішаний хор. Випуск 2. М. Гайворонський. Нью-Йорк, 1936. 2. Повік не зів''яне. Стрілецькі пісні Михайла Гайворонського. Упор. В. Подуфалий. Тернопіль, 1990.','народна пісня','Хлопці:
