INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_87603','Вставайте рано, татку','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1979','Фольклорні матеріали з отчого краю. Зібрали В.Сокіл та Г.Сокіл.- Львів, 1998','Зап. 16 грудня 1979 року В.Сокіл у с.Ялинкуватому від Коруд Агафії, 1921 року народж.','Вставайте рано, татку, (2)
Треба майити хатку.

