INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_883817','Підганяйте, хлопці, коней','Слова: Роман Купчинський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'аудіозапис',NULL,'Підганяйте, хлопці, коней,
Гляньте, неба край червоний,
Хмари захід заступили,
Буде з вітром сніг!

Підганяйте, не дрімайте
На вечерю поспішайте,
Хай же наші буйногриві
Не жаліють ніг!

Нас чекає там заплата -
Теплий усміх, ясна хата.
Гей, стелися під ногами
Зимове рядно.

Заки вихри в полі свиснуть,
Кришталеві чаші свиснуть,
А в тих чашах кришталевих -
Золоте вино...

"Чарка до чарки, серце до серця,
Стукнім на радість нас усіх.
Доля ловецька тому всміхнеться,
Хто любить чарку, спів і сміх.
Слава ловецтву, слава ловцям,
Слава несхибним стрільцям!"','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_883817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_883817','Підганяйте, хлопці, коней','Підганяйте, хлопці, коней,
