INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_883950','Було літо','Музика: народ Слова: народ','uk','ukraine_before_1917',NULL,NULL,'Український народний співаник, Мюнхен, 1946 р.',NULL,'Було літо, було літо,
Тай стала зима.
Як не було пригодоньки,
Гей, гей, та й досі нема.

Була ж йому пригодонька,
З Криму ідучи,
В чистім полю край дороги,
Гей, гей, воли пасучи.

Заслаб чумак-чумаченько,
Заслаб та й лежить,
Ніхто ж його не спитає,
Гей, гей, що в його болить.

Болять руки, болять ноги,
Болить голова...
Лишаються дрібні діти,
Гей, гей, жінка молода.

"Отамане-хазяїне,
Пожалій мене,
Іскинь свою сіру свиту,
Гей, гей, та накрий мене!

Отамане-хазяїне,
Мабуть, я умру, -
Зроби мені хазяїне,
Гей, гей, з клен-древа труну!"

"Ніде тобі, чумаченьку,
Клен-древа взять,
Будеш же ти, чумаченьку,
Гей, гей, в сосновій лежать!"

А в неділю рано-вранці
Та й вдарили в дзвін...
Це ж по тому чумакові,
Гей, гей, що їхав на Дін.

В понеділок рано-вранці
Та й вдарили в два...
Це ж по тому чумакові,
Гей, гей, що тепер нема!','[''pisni.org.ua'', ''cat:chumacki'', ''cat:socialno-pobutovi'', ''Чумацькі пісні'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_883950'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_883950','Було літо','Було літо, було літо,
Тай стала зима.
Як не було пригодоньки,
Гей, гей, та й досі нема.

Була ж йому пригодонька,
