INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_883373','Ой, перепеличка мала, невеличка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні Явдохи Зуїхи / Запис. Гнат Танцюра. - Київ: Наукова Думка, 1965. - 812 с.',NULL,'Ой перепеличка мала, невеличка,
Ой да люлі, мала, невеличка.

По полю літає, траву прогортає,
Ой да люлі, траву прогортає.

Траву розгортає, сокола шукає,
Ой да люлі, сокола шукає.

Соколоньку ясний, який ти прекрасний,
Ой да люлі, який ти прекрасний!

Соколе мій ясний, друже мій прекрасний,
Ой да люлі, друже мій прекрасний!

Будем говорити, як з тобою жити,
Ой да люлі, як з тобою жити.

Туман долиною, вітер дорогою,
Ой да люлі, вітер дорогою.

Вітер дорогою, мороз калиною,
Ой да люлі, мороз калиною.

Мороз калиною, козак дівчиною,
Ой да люлі, козак дівчиною','[''pisni.org.ua'', ''cat:podilski'', ''Пісні з Поділля'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_883373'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_883373','Ой, перепеличка мала, невеличка','Ой перепеличка мала, невеличка,
Ой да люлі, мала, невеличка.

По полю літає, траву прогортає,
Ой да люлі, траву прогортає.

Траву розгортає, сокола шукає,
Ой да люлі, сокола шукає.

Соколоньку ясний, який ти прекрасний,
Ой да люлі, який ти прекрасний!

Соколе мій ясний, друже мій прекрасний,
Ой да люлі, друже мій прекрасний!

Будем говорити, як з тобою жити,
Ой да люлі, як з тобою жити.

Туман долиною, вітер дорогою,
Ой да люлі, вітер дорогою.

Вітер дорогою, мороз калиною,
Ой да люлі, мороз калиною.

Мороз калиною, козак дівчиною,
Ой да люлі, козак дівчиною');
