INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_887272','Новацька коломийка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой з-за гаю зеленого
Вітер повіває,
А юнацтво у таборі
Любо день минає.

Приспів:
Ой дай дунай-дунай-дунай,
Ой дай дунай-дана
О-о-о, дай-дунай-дана.

Хто на збірці, хто на стірці,
Хто на прогулянці,
Цілий день в нас спів лунає,
Спів несеться вранці.

Приспів.

Коло лісу на полянці
Любим ігри грати,
В холодочку під деревцем
Любимо співати.

