INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_881878','Вишла дівчина','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://posydenky.lvivport.com',NULL,'Вишла дівчина, вишла єдина,
Яко з ружі квіт,
Ой стала, стала і заплакала,
Змінил ся єй світ.

"А што ж ти так плачеш,
А што ж так нарікаш, дівчино моя?"
"Як я не ма м плакать,
Як не мам нарікать? - Не буду твоя".

"Ой будеш, будеш, ой будеш, будеш,
Даст то милий Бог,
Люде ми тя раят і родичі кажут,
А сам судит Бог".

"Ти прийдеш вгору, ти прийдеш вгору,
А я в долину,.
Ти заквітнеш в ружу, ти заквітнеш в ружу,
А я - в калину".

"Кед ми зомреме, кед ми зомреме
Даме ми собі
Злати літери, злати літери
Вибить на гробі:

Ту лежит тіло, ту лежит тіло,
Ту лежат кості,
Котри зомрели, котри зомрели
З велької любості".','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_881878'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_881878','Вишла дівчина','Вишла дівчина, вишла єдина,
