INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_887409','Новацька вечірня молитва',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Боже, що дав нам цю днину,
