INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_887415','Новацький шлях','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Усі ми новачки в таборі,
Стаємо в лави з радістю в очах.
А наша пісня у просторі,
Лунає грімко по лісах, полях.

Від ранку до вечора
В таборі лунає спів -
Щоднини йде жваво наша гра
В таборі нoваків (новачок).

Несеться пісня ген у гори,
Де зеленіють дужі дерева,
Де нам прашок щебечуть хори,
Де нам шепоче квітка і трава.

Від ранку до вечора
В таборі лунає спів -
Щоднини йде жваво наша гра
В таборі нoваків (новачок).','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_887415'), datetime('now')),datetime('now'));
