INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_885611','Я кажу тобі добраніч','Музика: Чорні черешні Слова: Чорні черешні. Виконує: Чорні черешні','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Я кажу тобі добраніч, вишенько!
Добраніч, горішку!
Спи, моя люба смерічко!
До завтра, травичко!
Будь мудра, руденька білочко!
Ну чого ти смієшся, усмішко?

Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю.

Я чую, як калатає твоє серденько,
Я люблю тебе, зайченя мале!
А ти мені кажеш на вухо: "Добраніч!"
Тремтячи у піджамці своїй боровички.
Спи, засни, мій зайчик,
Спи, засни, добраніч...

Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю,
Ой, люлі-люлі-лю.

Я кажу тобі добраніч, вишенько!
Добраніч, горішку!','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_885611'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_885611','Я кажу тобі добраніч','Я кажу тобі добраніч, вишенько!
