INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_885450','У маю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'пласт',NULL,'Раз у неділю у маю
Пішла студентка до гаю.
За нею студент чап, чалап, чап
І за рученьку він її хап.

Ішли гаями і через ліс,
Вона втомилась, він її ніс,
А потім листя на купку склав,
І на коліно він її взяв.

А що там було — не скажу Вам,
Бо поміж ними не був я сам,
Пташки співали, зелений гай,
Бо час кохання — це місяць май.

Скінчилось літо, осінь прийшла,
Наша студентка в школу не йшла.
А як марець місяць наспів,
То було чути студентський спів:

"Ой люлі, люлі, спи, сину мій,
Молодий студент — це батько твій.
Ой люлі, люлі, спи, засипляй,
Бо час кохання — це місяць май."','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_885450'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_885450','У маю','Раз у неділю у маю
Пішла студентка до гаю.
За нею студент чап, чалап, чап
І за рученьку він її хап.

Ішли гаями і через ліс,
Вона втомилась, він її ніс,
А потім листя на купку склав,
І на коліно він її взяв.

А що там було — не скажу Вам,
Бо поміж ними не був я сам,
Пташки співали, зелений гай,
Бо час кохання — це місяць май.

Скінчилось літо, осінь прийшла,
Наша студентка в школу не йшла.
А як марець місяць наспів,
То було чути студентський спів:

"Ой люлі, люлі, спи, сину мій,
Молодий студент — це батько твій.
Ой люлі, люлі, спи, засипляй,
Бо час кохання — це місяць май."');
