INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_88373','Капелюх','Музика: Володимир Івасюк Слова: Володимир Івасюк. Виконує: Смерічка, Віктор Морозов, Піккардійська Терція, Назар Савко','uk','ukraine_before_1917',NULL,NULL,'http://ivasyuk.domivka.net/','Акорди (варіант 2) надав Taras Hryvul. Підбір акордів: Taras Hryvul','Як ішов селом я
В літнє надвечір''я,
Вітер капелюха
Звіяв на подвір''я,
Мого капелюха
Покотив подвір''ям.
Дівчина із хати
Вздріла і метнулась, —
Дала капелюха
Й весело всміхнулась,
Дала капелюха
І мені всміхнулась.
Йду сьогодні знову —
Вітру вже немає,
Свого капелюха
Сам туди кидаю.
Свого капелюха
Сам туди кидаю.
Вітру вже немає —
В серці завірюха,
Дівчини не видно —
Йду за капелюхом,
Йду усім курям на сміх
Сам за капелюхом.
Акорди (варіант 1):
G
Як ішов селом я в літнє надвечір''я
Вітер капелюха звіяв на подвір''я.
Мого капелюха покотив подвір''ям.','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_88373'), datetime('now')),datetime('now'));
