INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_888001','Щедрий вечір всім вам','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.yar-info.if.ua','Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Щедрий вечір всім вам, щаслива година!
Породила Діва пречистого Сина.
Приспів:
Ладо, Ладо, Ладо!
Все на світі радо,
Щедрий вечір на землі!
Не в пишних палатах Бога породила,
А в бідній стаєнці Господа вповила.
Приспів.
Не межи царями Господь наш явився,
А між вівчарами в яслах положився.
Приспів.
На світлім Востоці зоря засвітила,
Трьох царів премудрих вона звеселила.
Приспів.
Злато, ладан, миро Богу жертвували,
Христові в ясельцях поклін свій віддали.
Приспів.
І ми Христу-Богу наш поклін віддаймо,
Разом з пастирями весело співаймо!
Приспів.
Поклін свій віддаймо і станьмо просити,
Щоби землю нашу велів звеселити.
Приспів','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_888001'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_888001','Щедрий вечір всім вам','Щедрий вечір всім вам, щаслива година!
