INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_887714','Високо сиджу Далеко виджу',NULL,'uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Листки з приводу цієї Пісні: Поезія Астральних з''яв і реліґійні настрої. Питання походження людини в Колядкових мітах. Одною з найцікавіших загадок Колядкової космогонії є походження людини... Що означає ім''я "Коляда"? Порівняння слів Коляда і йому подібних у різних народів. Ориґінальна Українська назва Коляди — Калина. Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда) ― Святий Збір (Трійця) ― Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Високо сиджу Далеко виджу
