INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_888013','Небо ясні зірки вкрили','(Свят Вечір). Музика: народ Слова: народ','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: ― Святі Водорщі) ―: Дівич-Вечір...... Зелені Свята () ― Царинні Містерії...... Астральні Жнива... Рокове Коло.','Небо ясні зірки вкрили
Та всю землю освітили.
Щедрий вечір, добрий вечір
Усім людям на здоров''я.

Снігом ниви спорошило
На дорогу наносило.
Щедрий вечір, добрий вечір
Усім людям на здоров''я.

Добрий вечір, господарю,
Ми принесли тобі дари.
Щедрий вечір, добрий вечір
Усім людям на здоров''я.

Наші пісні - гарні дари,
Господарям для похвали.
Щедрий вечір, добрий вечір
Усім людям на здоров''я.

Боже Благий, Боже Щирий,
Пішли же нам рік щасливий.
Щедрий вечір, добрий вечір
Усім людям на здоров''я.','[''pisni.org.ua'', ''cat:narodni'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_888013'), datetime('now')),datetime('now'));
