INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8878','Ой у лузі','Музика: народна Слова: Степан Чарнецький, Григорій Трух. Виконує: Етнографічний хор Гомін, Не журись!, Олександр Малінін','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'1. Пісневир. Молодіжний співаник.– Львів, 2001 2. Аудіо-CD "Володимир Вермінський. Йшли селом партизани" (2002) 3. Сурма. Збірник воєнних пісень.- Львів-Київ: Червона Калина, 1922.– c. 8–10','Текст взято із джерела 1. Можливо, автором музики є Філарет Колесса. У джерелі 3 вказано: "Народна мел. Сл.: Гр. Трух. Гарм.: М. Гайворонський". Варіант тексту за джерелом 3: * Машерують наші добровольці у кровавий тан, Визволяти наших Українців з московських кайдан. А ми наших братів-Українців визволимо, А ми нашу славну Україну, гей! гей! розвеселимо! ** Гей у полі ярої пшенички золотистий лан, Розпочали Стрільці Українські з Москалями тан. Акорди підібрано на слух за джерелом 2. Оригінальна тональність за джерелом 2: F#m. Підбір акордів: bohdanko','Ой у лузі червона калина похилилася,
Чогось наша славна Україна зажурилася,
А ми тую червону калину підіймемо,
А ми нашу славну Україну, гей, гей, розвеселимо!
Марширують наші добровольці у кривавий тан,
Визволяти братів-українців з московських кайдан.
А ми тії московські кайдани розірвемо,
А ми нашу славну Україну, гей, гей, розвеселимо!*
Гей, у полі ярої пшенички золотистий лан,
Розпочали Січовії Стрільці з москалями тан.**
А ми тую ярую пшеничку ізберемо,
А ми нашу славну Україну, гей, гей, розвеселимо!
Як повіє буйнесенький вітер з широких степів,
То прославить по всій Україні Січових Стрільців.
А ми тую стрілецькую славу збережемо,
А ми нашу славну Україну, гей, гей, розвеселимо!
Акорди (варіант 2):
Ой у лузі червона калина похилилася,
Чогось наша славна Україна зажурилася,
А ми тую червону калину підіймемо,
А ми нашу славну Україну, гей, гей, розвеселимо!','[''pisni.org.ua'', ''cat:patriotic'', ''cat:strilecki'', ''Патріотичні пісні'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8878'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8878','Ой у лузі','Ой у лузі червона калина похилилася,
Чогось наша славна Україна зажурилася,
А ми тую червону калину підіймемо,
