INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_88501','Канни зів’яли','Музика: Руслан Іщук Слова: Федір Пігович. Виконує: Опришки','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Речитатив:
Канни - квіти багряні,
Квіти кохання дарую тобі,
Моя кохана...

Лелеки покинули гнізда,
Тумани лягли вдалині...
Чому ти, кохана, так пізно
З''явилась до мене вві сні?

Приспів:
Канни зів''яли, канни мої,
Квіти багряні, кохання, жалю,
Канни зів''яли, канни мої,
Квіти багряні, кохання, жалю.

Коли вечори багряніли,
Мов каннів вогні чарівні,
Тобі дарував я несміло
Квіток пелюстки чарівні.

Приспів.

До пізньої осені канни
На клумбах багряних цвітуть.
Вони в мої мрії, кохана,
Надії й тривоги вплетуть.

Приспів.

Речитатив:
Канни - квіти багряні,
Квіти кохання дарую тобі,
Моя навіки забута кохана...
Канни','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_88501'), datetime('now')),datetime('now'));
