INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_88205','Ой служив я в пана','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Anrzej (член клубу) Ще співають так (почув на Перемишлянщині саме в такому порядку): Ой служив я в пана Та й на восьме літо - Заслужив я в пана Кобилу за літо. А кобила сіно везла, Хвіст задерла - в дупу змерзла, А та дівка напилася, Впала з п''єца, забилася. А той баран круторогий - Скочив бабі межи ноги, А те теля хвостом виля, А той індик дик-дик, дик-дик, (піндик, піндик,) А те гуся суся-сюся, А те кача дрібно скаче, А та кура-чубатура По садочку ходить та й ходить, Куряточок водить та й водить.','Як служив  я в пана
Та й першеє літо та й літо -
Заслужив я у пана
Курочку за літо.

А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Як служив же я в пана
Та й другеє літо та й літо -
Заслужив я у пана
Качечку за літо.

А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Як служив же я в пана
Та й третєє літо та літо -
Заслужив я у пана
Гусочку за літо.

А те гуся суся-сюся,
А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Як служив же я в пана
Та й четверте літо та літо -
Заслужив я у пана
Індика за літо.

А той індик дик-дик, дик-дик,
А те гуся суся-сюся,
А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Як служив же я в пана
Та й на п''яте літо та й літо -
Заслужив же я у пана
Барана за літо.

А той баран круторогий -
Поламав він собі ноги,
А той індик дик-дик, дик-дик,
А те гуся суся-сюся,
А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Ой служив же я в пана
Та й на шосте літо та й літо -
Заслужив же я у пана
Телятко за літо.

А те теля хвостом виля,
А той баран круторогий -
Поламав він собі ноги,
А той індик дик-дик, дик-дик,
А те гуся суся-сюся,
А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.

Як служив же я в пана
Та й на сьоме літо та й літо -
Заслужив же я у пана
Дівчину за літо.

А та дівка напилася,
Впала з печі, забилася.
А те теля хвостом виля,
А той баран круторогий -
Поламав він собі ноги,
А той індик дик-дик, дик-дик,
А те гуся суся-сюся,
А те кача дрібно скаче,
А та курка-чубатурка
По садочку ходить та й ходить,
Курчаточок водить та й водить.    Фонограма-мінус (mp3, 320 kbps)','[''pisni.org.ua'', ''cat:narodni'', ''cat:zhartivlyvi'', ''Народні пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_88205'), datetime('now')),datetime('now'));
