INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_888154','Зажурилася Крутая Гора','Музика: народ Слова: народ','uk','ukraine_before_1917',NULL,NULL,'Колядки і щедрівки. - К.: Музична Україна. - 1991. - 240 с.','Колядка Дівчині. Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Зажурилася крутая гора,
Що не зродила шовкова трава.

Але зродило зелене вино,
Зелене вино вгору си вило.

Вгору си вило, рясно зацвіло.
Єго стерегла гречная панна.

Гречная панна на йм''я Марійка.
Ой стережучи, она заснула.

За своє винце вона забула.
Прилетіли ж бо три райські пташки.

Вни о тім часі прибути ласі.
- Ой шуги-луги, райськії пташки.

Ой не спивайте зелене вино,
Ой не з''їдайте зелене вино!

Бо мені вина дуже потрібно:
Маю сестричку на відданічку.

Маю братчика на оженічку,
Я сама також ой заручена.

Ой заручена й аж до Галича,
Й аж до Галича та й за панича.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_888154'), datetime('now')),datetime('now'));
