INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_892950','Найкраще місто','Українська народна пісня. Виконує: Оксана Білозір','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Під замком на горбах в долині
Зеленогривий гордий Львів.
Вже восьмий вік іде, як сину
Данило князь тут місто звів.
Цей град краси суцвіття храмів -
Моя колиска золота.
Тут я зростала поміж львами
З піснями в серці й на вустах.

Приспів:
Найкраще місто на землі
Для мене ти, мій Львове.
Ти мій Париж, маленький Рим,
О, рідний мій, чудовий.
Найкраще місто на землі -
Ти, мій Львове.

З твоїх долонь твердих спиваю
Наснагу й силу в тяжкі дні.
Твоїми болями страждаю,
Твій спів відлунює в мені.
Коли ж, як сніг в тобі розтану,
Злечу хмариною у вись,
Я піснею твоєю стану,
Зігрію камінь, як колись.

Приспів. (2)

Найкраще місто на землі -
Ти, мій Львове.','[''pisni.org.ua'', ''cat:lviv'', ''Пісні про Львів'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_892950'), datetime('now')),datetime('now'));
